            {hasPermission('perm_view_fullscreen') && (
                <button onClick={handleToggleFullscreen} className="bg-gray-700 hover:bg-gray-600 text-white p-2 rounded-lg text-sm font-semibold flex items-center gap-1 shadow-md" title={isFullscreen ? t('fullscreen_off') : t('fullscreen_on')}>
