    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path d="M8 3a1 1 0 011-1h2a1 1 0 110 2H9a1 1 0 01-1-1z" /><path d="M6 3a2 2 0 00-2 2v11a2 2 0 002 2h8a2 2 0 002-2V5a2 2 0 00-2-2 3 3 0 01-3 3H9a3 3 0 01-3-3z" /></svg>
);

const ChatIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10c0 3.866-3.582 7-8 7a8.841 8.841 0 01-4.083-.98L2 17l1.338-3.123C2.493 12.767 2 11.434 2 10c0-3.866 3.582-7 8-7s8 3.134 8 7zM7 9H5v2h2V9zm8 0h-2v2h2V9zM9 9h2v2H9V9z" clipRule="evenodd" /></svg>
);

const ReturnIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 010 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" clipRule="evenodd" /></svg>
);

const XMarkIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
    </svg>
);

const TaskList: React.FC<TaskListProps> = (props) => {
    const { t } = useLanguage();

    // Edit Mode State
    const [editingId, setEditingId] = useState<string | null>(null);
    const [editVal, setEditVal] = useState('');
    const [editPrio, setEditPrio] = useState<PriorityLevel>('NORMAL');

    // Missing Reason Modal State
    const [missingId, setMissingId] = useState<string | null>(null);

    // Note Modal State
    const [noteId, setNoteId] = useState<string | null>(null);
    const [noteVal, setNoteVal] = useState('');

    // Copy Feedback State
    const [copiedId, setCopiedId] = useState<string | null>(null);

    const startEditing = (task: Task) => {
        setEditingId(task.id);
        setEditVal(task.text);
        setEditPrio(task.priority || 'NORMAL');
        setMissingId(null);
        setNoteId(null);
    };

    const saveEdit = (id: string) => {
        if (editVal.trim()) {
            props.onEditTask(id, editVal, editPrio);
            setEditingId(null);
        }
    };

    const handleMissingClick = (id: string) => {
        setMissingId(missingId === id ? null : id);
        setEditingId(null);
        setNoteId(null);
    };

    const confirmMissing = (id: string, reason: string) => {
        props.onToggleMissing(id, reason);
        setMissingId(null);
    };

    const handleNoteClick = (task: Task) => {
        setNoteId(noteId === task.id ? null : task.id);
        setNoteVal(task.note || '');
        setEditingId(null);
        setMissingId(null);
    };

    const saveNote = (id: string) => {
        props.onAddNote(id, noteVal);
        setNoteId(null);
    };

    const handleCopyPart = (id: string, text: string) => {
        if (!text) return;
        navigator.clipboard.writeText(text).then(() => {
            setCopiedId(id);
            setTimeout(() => setCopiedId(null), 1500);
        }).catch(err => console.error('Copy failed', err));
    };

    return (
        <div className="flex flex-col space-y-3 pb-20">
            {props.tasks.length === 0 && (
                <div className="text-center py-12 text-gray-500 italic bg-gray-800 rounded-xl border border-gray-700">
                    {t('empty_tasks')}
                </div>
            )}

            {props.tasks.map((task) => {
                const isEditing = editingId === task.id;
                const showMissingOptions = missingId === task.id;
                const showNoteInput = noteId === task.id;

                // Determine background style
                let bgClass = "";
                let borderClass = "";
                let textClass = "text-white";

                if (task.isDone) {
                     if (task.status === 'incorrectly_entered') {
                         bgClass = "bg-gray-800 opacity-60";
                         textClass = "text-gray-500 line-through";
                     } else if (task.isMissing) {
                        bgClass = "bg-red-900/50";
                        borderClass = "border-l-4 border-red-600";
                     } else {
                        bgClass = "bg-gray-800 opacity-80";
                        textClass = "text-gray-500 line-through";
                     }
                } else {
                    if (task.isInProgress) {
                        bgClass = "bg-[#0B1121]"; // Very dark blue for active
                        borderClass = "border-l-4 border-blue-500";
                    } else if (task.isMissing) {
                        bgClass = "bg-red-800";
                        borderClass = "border-l-4 border-red-500";
                    } else if (task.priority === 'URGENT') {
                        bgClass = "bg-[#0B1121]";
                        borderClass = "border-l-4 border-red-600";
                    } else {
                        bgClass = "bg-[#0B1121]"; // Deep blue
                        borderClass = "border-l-4 border-blue-900";
                    }
                }

                return (
                    <div key={task.id} className={`group relative flex flex-row rounded-lg shadow-md overflow-hidden transition-all duration-200 items-stretch ${bgClass} ${borderClass} ${!task.isDone ? 'hover:shadow-lg' : ''}`}>

                        {/* LEFT SECTION: Stacks vertically on mobile, row on desktop */}
                        <div className="flex-grow flex flex-col sm:flex-row sm:items-center">

                            {/* 1. Part Info (Top on mobile, Left on desktop) - Grows to fill space */}
                            <div className="flex-grow p-3 flex flex-col justify-center min-w-0">
                                {isEditing ? (
                                    <div className="space-y-2 bg-gray-900 p-2 rounded border border-gray-700 z-10">
                                        <textarea 
                                            value={editVal} 
                                            onChange={(e) => setEditVal(e.target.value)} 
                                            className="w-full bg-gray-800 text-white p-2 rounded border border-gray-600 text-sm focus:border-teal-500 outline-none"
                                            rows={2}
                                        />
                                        <div className="flex gap-2">
                                            <button onClick={() => saveEdit(task.id)} className="flex-1 bg-teal-600 text-white py-1 rounded text-xs font-bold">{t('btn_save')}</button>
                                            <button onClick={() => setEditingId(null)} className="flex-1 bg-gray-700 text-white py-1 rounded text-xs font-bold">{t('btn_cancel')}</button>
                                        </div>
                                    </div>
                                ) : (
                                    <>
                                        <div className="flex items-baseline gap-2">
                                            <h3 className={`text-lg sm:text-2xl font-bold truncate pr-2 leading-tight ${textClass}`}>
                                                {task.partNumber || task.text}
                                            </h3>
                                            {task.note && <span className="text-yellow-500" title={task.note}><ChatIcon className="w-5 h-5" /></span>}
                                        </div>
                                        <div className="mt-1 flex flex-wrap gap-2 items-center">
                                            <span className={`text-sm sm:text-base font-bold uppercase tracking-wider ${task.isDone ? 'text-gray-600' : 'text-cyan-400'}`}>
                                                {task.workplace || "---"}
                                            </span>
                                            {task.isDone && !task.isMissing && (
                                                <span className="text-green-500 flex items-center gap-1 text-xs font-mono">
                                                    <CheckIcon className="w-3 h-3" /> {task.completedBy} • {task.completedAt ? new Date(task.completedAt).toLocaleTimeString() : ''}
                                                </span>
                                            )}
                                             {task.isMissing && (
                                                <span className="text-red-300 flex items-center gap-1 text-xs font-bold uppercase">
                                                    <ExclamationIcon className="w-3 h-3" /> {task.missingReason}
                                                </span>
                                            )}
                                        </div>
                                    </>
                                )}
                            </div>

                            {/* 2. Meta + Controls (Bottom on mobile, Right on desktop) */}
                            {!isEditing && (
                                <div className="flex items-center justify-between sm:justify-end gap-3 p-2 bg-black/10 sm:bg-transparent border-t sm:border-t-0 border-white/5">

                                    {/* Meta Information (Left of buttons) */}
                                    <div className="flex flex-col items-end min-w-[80px]">
                                        {task.quantity ? (
                                            <span className={`text-3xl sm:text-4xl font-extrabold ${task.isDone ? 'text-gray-500' : 'text-teal-400'}`}>
                                                {task.quantity} <span className="text-sm font-normal text-gray-400">{task.quantityUnit === 'pcs' ? 'ks' : task.quantityUnit === 'boxes' ? 'box' : 'pal'}</span>
                                            </span>
                                        ) : (
                                            <span className="text-2xl font-bold text-gray-600">-</span>
                                        )}
                                        <div className="text-xs text-gray-400 text-right leading-tight mt-1">
                                            <div className="font-bold text-gray-500">{task.createdBy}</div>
                                            <div>{new Date(task.createdAt || 0).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</div>
                                        </div>
                                    </div>

                                    {/* Main Buttons (Centered vertically in row) */}
                                    <div className="flex items-center gap-1 sm:gap-2">
                                        {!task.isDone ? (
                                            <>
                                                {/* Copy Button */}
                                                {props.hasPermission('perm_btn_copy') && (
                                                    <button 
                                                        onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                        className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${
                                                            copiedId === task.id 
                                                            ? 'bg-green-600 border-green-500 text-white' 
                                                            : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                        }`} 
                                                        title={t('btn_copy')}
                                                    >
                                                        {copiedId === task.id ? (
                                                            <span className="font-extrabold text-xs">OK</span>
                                                        ) : (
                                                            <CopyIcon className="w-7 h-7 sm:w-8 sm:h-8" />
                                                        )}
                                                    </button>
                                                )}

                                                {/* Lock */}
                                                {props.hasPermission('perm_btn_lock') && (
                                                    <button onClick={() => props.onToggleBlock(task.id)} className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg ${task.isBlocked ? 'bg-red-600 text-white ring-2 ring-red-400' : 'bg-gray-700 text-gray-400 hover:bg-gray-600 border border-gray-600'}`} title={t('perm_btn_lock')}>
                                                        <LockIcon className="w-7 h-7 sm:w-8 sm:h-8" />
                                                    </button>
                                                )}

                                                {/* Play/Pause */}
                                                {props.hasPermission('perm_btn_resolve') && (
                                                    <button onClick={() => props.onSetInProgress(task.id)} className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg ${task.isInProgress ? 'bg-yellow-600 text-white animate-pulse ring-2 ring-yellow-400' : 'bg-gray-700 text-yellow-500 hover:bg-gray-600 border border-gray-600'}`} title={t('status_resolving')}>
                                                        {task.isInProgress ? <PauseIcon className="w-8 h-8 sm:w-9 sm:h-9" /> : <PlayIcon className="w-8 h-8 sm:w-9 sm:h-9" />}
                                                    </button>
                                                )}

                                                {/* Missing */}
                                                {props.hasPermission('perm_btn_missing') && (
                                                    <button onClick={() => handleMissingClick(task.id)} className="w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-gray-700 text-red-500 hover:bg-gray-600 hover:text-red-400 transition-all active:scale-95 shadow-lg border border-gray-600" title={t('perm_btn_missing')}>
                                                        <ExclamationIcon className="w-8 h-8 sm:w-9 sm:h-9" />
                                                    </button>
                                                )}

                                                {/* Finish (Biggest) */}
                                                {props.hasPermission('perm_btn_finish') && (
                                                    <button onClick={() => props.onToggleTask(task.id)} className="w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-teal-600 text-white hover:bg-teal-500 transition-all active:scale-95 shadow-xl border border-teal-500" title={t('btn_finish')}>
                                                        <CheckIcon className="w-9 h-9 sm:w-10 sm:h-10" />
                                                    </button>
                                                )}
                                            </>
                                        ) : (
                                            /* Done Actions */
                                            <div className="flex items-center gap-1 sm:gap-2">
                                                {/* Copy Button for Done Tasks */}
                                                {props.hasPermission('perm_btn_copy') && (
                                                    <button 
                                                        onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                        className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${
                                                            copiedId === task.id 
                                                            ? 'bg-green-600 border-green-500 text-white' 
                                                            : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                        }`} 
                                                        title={t('btn_copy')}
                                                    >
                                                        {copiedId === task.id ? (
                                                            <span className="font-extrabold text-xs">OK</span>
                                                        ) : (
                                                            <CopyIcon className="w-7 h-7 sm:w-8 sm:h-8" />
                                                        )}
                                                    </button>
                                                )}
                                                {props.hasPermission('perm_btn_return') && (
                                                    <button 
                                                        onClick={() => props.onToggleTask(task.id)} 
                                                        className="w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-orange-600 hover:bg-orange-500 text-white shadow-md transition-all active:scale-95 border border-orange-500" 
                                                        title={t('btn_stop')}
                                                    >
                                                        <ReturnIcon className="w-8 h-8 sm:w-9 sm:h-9" />
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* RIGHT FIXED COLUMN: Secondary Actions (Fixed width) */}
                        <div className="flex flex-col w-12 sm:w-14 border-l border-white/10 bg-black/30 shrink-0">
                             {props.hasPermission('perm_btn_note') && (
                                <button onClick={() => handleNoteClick(task)} className={`flex-1 flex items-center justify-center transition-colors ${task.note ? 'text-yellow-400 bg-yellow-900/20' : 'text-gray-400 hover:text-white hover:bg-white/5'}`} title={t('btn_note')}>
                                    <ChatIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                             {props.hasPermission('perm_btn_edit') && !task.isDone && (
                                <button onClick={() => startEditing(task)} className="flex-1 flex items-center justify-center text-blue-400 hover:text-blue-300 hover:bg-white/5 border-t border-white/5 transition-colors" title={t('perm_btn_edit')}>
                                    <EditIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                             {props.hasPermission('perm_btn_incorrect') && task.status !== 'incorrectly_entered' && (
                                <button onClick={() => { if(window.confirm(t('incorrect_confirm'))) props.onMarkAsIncorrect(task.id); }} className="flex-1 flex items-center justify-center text-orange-500 hover:text-orange-400 hover:bg-white/5 border-t border-white/5 transition-colors" title={t('btn_mark_incorrect')}>
                                    <XMarkIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                             {props.hasPermission('perm_btn_delete') && (
                                <button onClick={() => { if(window.confirm(t('miss_delete_confirm'))) props.onDeleteTask(task.id); }} className="flex-1 flex items-center justify-center text-red-500 hover:text-red-400 hover:bg-white/5 border-t border-white/5 transition-colors" title={t('perm_btn_delete')}>
                                    <TrashIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                        </div>

                        {/* Modals Overlay */}
                        {(showMissingOptions || showNoteInput) && (
                            <div className="absolute inset-0 bg-gray-900/95 z-20 flex flex-col justify-center p-4">
                                {showMissingOptions && (
                                    <div className="space-y-2">
                                        <h4 className="text-red-400 font-bold mb-2">{t('modal_missing_title')}</h4>
                                        <div className="grid grid-cols-2 gap-2">
                                            {props.missingReasons.map(r => (
                                                <button key={r.id} onClick={() => confirmMissing(task.id, r.value)} className="p-3 bg-gray-800 border border-gray-600 hover:border-red-500 hover:bg-gray-700 text-white rounded-lg text-sm font-bold transition-colors">
                                                    {r.value}
                                                </button>
                                            ))}
                                        </div>
                                        <button onClick={() => setMissingId(null)} className="w-full mt-3 py-3 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700 font-bold">{t('btn_cancel')}</button>
                                    </div>
                                )}
                                {showNoteInput && (
                                    <div className="space-y-2">
                                        <h4 className="text-yellow-400 font-bold mb-2">{t('btn_note')}</h4>
                                        <textarea 
                                            value={noteVal} 
                                            onChange={(e) => setNoteVal(e.target.value)} 
                                            className="w-full bg-gray-800 text-white p-3 rounded-lg border border-gray-600 focus:border-yellow-500 outline-none" 
                                            rows={3}
                                            autoFocus
                                        />
                                        <div className="flex gap-2">
                                            <button onClick={() => saveNote(task.id)} className="flex-1 bg-yellow-600 hover:bg-yellow-500 text-white py-3 rounded-lg font-bold transition-colors">{t('btn_save')}</button>
                                            <button onClick={() => setNoteId(null)} className="flex-1 bg-gray-800 hover:bg-gray-700 text-gray-400 py-3 rounded-lg font-bold transition-colors">{t('btn_cancel')}</button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}

                    </div>
                );
            })}
        </div>
    );
};

export default TaskList;

import React, { useState } from 'react';
import { Task, PriorityLevel, DBItem } from '../App';
import { useLanguage } from './LanguageContext';

interface TaskListProps {
  currentUser: 'ADMIN' | 'USER' | 'SUPERVISOR' | 'LEADER' | 'LOGISTICIAN';
  currentUserName: string;
  tasks: Task[];
  missingReasons: DBItem[];
  onToggleTask: (id: string) => void;
  onEditTask: (id: string, newText: string, newPriority?: PriorityLevel) => void;
  onDeleteTask: (id: string) => void;
  onToggleMissing: (id: string, reason?: string) => void;
  onSetInProgress: (id: string) => void;
  onToggleBlock: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  onAddNote: (id: string, note: string) => void;
  onReleaseTask: (id: string) => void;
  hasPermission: (perm: string) => boolean;
}

