      {/* Break Active Banner */}
      {props.isBreakActive && (
        <div className="bg-orange-800 text-white text-center py-2 px-4 shadow-md font-bold text-sm z-20">
          {t('break_active')} - {t('break_active_desc')}
        </div>
      )}

      {/* Success Message */}
      {showSuccessMessage && (
        <div className="fixed top-20 right-4 bg-green-600 text-white p-4 rounded-lg shadow-xl z-50 animate-bounce">
          {t('sent_msg')}
