                onToggleTask={props.onToggleTask} 
                onEditTask={props.onEditTask} 
                onDeleteTask={props.onDeleteTask} 
                onToggleMissing={props.onToggleMissing}
                onSetInProgress={props.onSetInProgress}
                onToggleBlock={props.onToggleBlock}
