const TaskList: React.FC<TaskListProps> = (props) => {
    const { t } = useLanguage();

    // Edit Mode State
    const [editingId, setEditingId] = useState<string | null>(null);
    const [editVal, setEditVal] = useState('');
    const [editPrio, setEditPrio] = useState<PriorityLevel>('NORMAL');

    // Missing Reason Modal State
    const [missingId, setMissingId] = useState<string | null>(null);

    // Note Modal State (Still inline/local for context)
    const [noteId, setNoteId] = useState<string | null>(null);
    const [noteVal, setNoteVal] = useState('');

    // Copy Feedback State
    const [copiedId, setCopiedId] = useState<string | null>(null);

    const startEditing = (task: Task) => {
        setEditingId(task.id);
        setEditVal(task.text);
        setEditPrio(task.priority || 'NORMAL');
        setMissingId(null);
        setNoteId(null);
    };

    const saveEdit = (id: string) => {
        if (editVal.trim()) {
            props.onEditTask(id, editVal, editPrio);
            setEditingId(null);
        }
    };

    const handleMissingClick = (task: Task) => {
        if (task.isMissing) {
            // Logic to cancel missing status
            if (props.hasPermission('perm_btn_cancel_missing')) {
                if (window.confirm(t('cancel_missing_confirm'))) {
                     props.onToggleMissing(task.id);
                }
            } else {
                alert(t('action_not_allowed'));
            }
        } else {
            // Standard open modal logic
            setMissingId(missingId === task.id ? null : task.id);
            setEditingId(null);
            setNoteId(null);
        }
    };

    const confirmMissing = (id: string, reason: string) => {
        props.onToggleMissing(id, reason);
        setMissingId(null);
    };

    const handleNoteClick = (task: Task) => {
        setNoteId(noteId === task.id ? null : task.id);
        setNoteVal(task.note || '');
        setEditingId(null);
        setMissingId(null);
    };

    const saveNote = (id: string) => {
        props.onAddNote(id, noteVal);
        setNoteId(null);
    };

    const handleCopyPart = (id: string, text: string) => {
        if (!text) return;
        navigator.clipboard.writeText(text).then(() => {
            setCopiedId(id);
            setTimeout(() => setCopiedId(null), 1500);
        }).catch(err => console.error('Copy failed', err));
    };

    return (
        <div className="flex flex-col space-y-3 pb-20">
            {props.tasks.length === 0 && (
                <div className="text-center py-12 text-gray-500 italic bg-gray-800 rounded-xl border border-gray-700">
                    {t('empty_tasks')}
                </div>
            )}

            {props.tasks.map((task) => {
                const isEditing = editingId === task.id;
                // Removed showMissingOptions from here to prevent inline rendering
                const showNoteInput = noteId === task.id;

                // Determine background style
                let bgClass = "";
                let borderClass = "";
                let textClass = "text-white";

                if (task.isDone) {
                     if (task.status === 'incorrectly_entered') {
                         bgClass = "bg-gray-800 opacity-60";
                         textClass = "text-gray-500 line-through";
                     } else if (task.isMissing) {
                        bgClass = "bg-red-900/50";
                        borderClass = "border-l-4 border-red-600";
                     } else {
                        bgClass = "bg-gray-800 opacity-80";
                        textClass = "text-gray-500 line-through";
                     }
                } else {
                    if (task.isInProgress) {
                        bgClass = "bg-[#0B1121]"; // Very dark blue for active
                        borderClass = "border-l-4 border-blue-500";
                    } else if (task.isMissing) {
                        bgClass = "bg-red-800";
                        borderClass = "border-l-4 border-red-500";
                    } else if (task.priority === 'URGENT') {
                        bgClass = "bg-[#0B1121]";
                        borderClass = "border-l-4 border-red-600";
                    } else {
                        bgClass = "bg-[#0B1121]"; // Deep blue
                        borderClass = "border-l-4 border-blue-900";
                    }
                }

                return (
                    <div key={task.id} className={`group relative flex flex-row rounded-lg shadow-md overflow-hidden transition-all duration-200 items-stretch ${bgClass} ${borderClass} ${!task.isDone ? 'hover:shadow-lg' : ''}`}>

                        {/* LEFT SECTION: Stacks vertically on mobile, row on desktop */}
                        <div className="flex-grow flex flex-col sm:flex-row sm:items-center">

                            {/* 1. Part Info (Top on mobile, Left on desktop) - Grows to fill space */}
                            <div className="flex-grow p-3 flex flex-col justify-center min-w-0">
                                {isEditing ? (
                                    <div className="space-y-2 bg-gray-900 p-2 rounded border border-gray-700 z-10">
                                        <textarea 
                                            value={editVal} 
                                            onChange={(e) => setEditVal(e.target.value)} 
                                            className="w-full bg-gray-800 text-white p-2 rounded border border-gray-600 text-sm focus:border-teal-500 outline-none"
                                            rows={2}
                                        />
                                        <div className="flex gap-2">
                                            <button onClick={() => saveEdit(task.id)} className="flex-1 bg-teal-600 text-white py-1 rounded text-xs font-bold">{t('btn_save')}</button>
                                            <button onClick={() => setEditingId(null)} className="flex-1 bg-gray-700 text-white py-1 rounded text-xs font-bold">{t('btn_cancel')}</button>
                                        </div>
                                    </div>
                                ) : (
                                    <>
                                        <div className="flex items-baseline gap-2">
                                            <h3 className={`text-lg sm:text-2xl font-bold truncate pr-2 leading-tight ${textClass}`}>
                                                {task.partNumber || task.text}
                                            </h3>
                                            {task.note && <span className="text-yellow-500" title={task.note}><ChatIcon className="w-5 h-5" /></span>}
                                        </div>
                                        <div className="mt-1 flex flex-wrap gap-2 items-center">
                                            <span className={`text-sm sm:text-base font-bold uppercase tracking-wider ${task.isDone ? 'text-gray-600' : 'text-cyan-400'}`}>
                                                {task.workplace || "---"}
                                            </span>
                                            {task.isDone && !task.isMissing && (
                                                <span className="text-green-500 flex items-center gap-1 text-xs font-mono">
                                                    <CheckIcon className="w-3 h-3" /> {task.completedBy} • {task.completedAt ? new Date(task.completedAt).toLocaleTimeString() : ''}
                                                </span>
                                            )}
                                             {task.isMissing && (
                                                <span className="text-red-300 flex items-center gap-1 text-xs font-bold uppercase">
                                                    <ExclamationIcon className="w-3 h-3" /> {task.missingReason}
                                                </span>
                                            )}
                                        </div>
                                    </>
                                )}
                            </div>

                            {/* 2. Meta + Controls (Bottom on mobile, Right on desktop) */}
                            {!isEditing && (
                                <div className="flex items-center justify-between sm:justify-end gap-3 p-2 bg-black/10 sm:bg-transparent border-t sm:border-t-0 border-white/5">

                                    {/* Meta Information (Left of buttons) */}
                                    <div className="flex flex-col items-end min-w-[80px]">
                                        {task.quantity ? (
                                            <span className={`text-3xl sm:text-4xl font-extrabold ${task.isDone ? 'text-gray-500' : 'text-teal-400'}`}>
                                                {task.quantity} <span className="text-sm font-normal text-gray-400">{task.quantityUnit === 'pcs' ? 'ks' : task.quantityUnit === 'boxes' ? 'box' : 'pal'}</span>
                                            </span>
                                        ) : (
                                            <span className="text-2xl font-bold text-gray-600">-</span>
                                        )}
                                        <div className="text-xs text-gray-400 text-right leading-tight mt-1">
                                            <div className="font-bold text-gray-500">{task.createdBy}</div>
                                            <div>{new Date(task.createdAt || 0).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</div>
                                        </div>
                                    </div>

                                    {/* Main Buttons (Centered vertically in row) */}
                                    <div className="flex items-center gap-1 sm:gap-2">
                                        {!task.isDone ? (
                                            <>
                                                {/* Copy Button */}
                                                {props.hasPermission('perm_btn_copy') && (
                                                    <button 
                                                        onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                        className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${
                                                            copiedId === task.id 
                                                            ? 'bg-green-600 border-green-500 text-white' 
                                                            : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                        }`} 
                                                        title={t('btn_copy')}
                                                    >
                                                        {copiedId === task.id ? (
                                                            <span className="font-extrabold text-xs">OK</span>
                                                        ) : (
                                                            <CopyIcon className="w-7 h-7 sm:w-8 sm:h-8" />
                                                        )}
                                                    </button>
                                                )}

                                                {/* Lock */}
                                                {props.hasPermission('perm_btn_lock') && (
                                                    <button onClick={() => props.onToggleBlock(task.id)} className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg ${task.isBlocked ? 'bg-red-600 text-white ring-2 ring-red-400' : 'bg-gray-700 text-gray-400 hover:bg-gray-600 border border-gray-600'}`} title={t('perm_btn_lock')}>
                                                        <LockIcon className="w-7 h-7 sm:w-8 sm:h-8" />
                                                    </button>
                                                )}

                                                {/* Play/Pause */}
                                                {props.hasPermission('perm_btn_resolve') && (
                                                    <button onClick={() => props.onSetInProgress(task.id)} className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg ${task.isInProgress ? 'bg-yellow-600 text-white animate-pulse ring-2 ring-yellow-400' : 'bg-gray-700 text-yellow-500 hover:bg-gray-600 border border-gray-600'}`} title={t('status_resolving')}>
                                                        {task.isInProgress ? <PauseIcon className="w-8 h-8 sm:w-9 sm:h-9" /> : <PlayIcon className="w-8 h-8 sm:w-9 sm:h-9" />}
                                                    </button>
                                                )}

                                                {/* Missing */}
                                                {props.hasPermission('perm_btn_missing') && (
                                                    <button onClick={() => handleMissingClick(task)} className="w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-gray-700 text-red-500 hover:bg-gray-600 hover:text-red-400 transition-all active:scale-95 shadow-lg border border-gray-600" title={t('perm_btn_missing')}>
                                                        <ExclamationIcon className="w-8 h-8 sm:w-9 sm:h-9" />
                                                    </button>
                                                )}

                                                {/* Finish (Biggest) */}
                                                {props.hasPermission('perm_btn_finish') && (
                                                    <button onClick={() => props.onToggleTask(task.id)} className="w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-teal-600 text-white hover:bg-teal-500 transition-all active:scale-95 shadow-xl border border-teal-500" title={t('btn_finish')}>
                                                        <CheckIcon className="w-9 h-9 sm:w-10 sm:h-10" />
                                                    </button>
                                                )}
                                            </>
                                        ) : (
                                            /* Done Actions */
                                            <div className="flex items-center gap-1 sm:gap-2">
                                                {/* Copy Button for Done Tasks */}
                                                {props.hasPermission('perm_btn_copy') && (
                                                    <button 
                                                        onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                        className={`w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${
                                                            copiedId === task.id 
                                                            ? 'bg-green-600 border-green-500 text-white' 
                                                            : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                        }`} 
                                                        title={t('btn_copy')}
                                                    >
                                                        {copiedId === task.id ? (
                                                            <span className="font-extrabold text-xs">OK</span>
                                                        ) : (
                                                            <CopyIcon className="w-7 h-7 sm:w-8 sm:h-8" />
                                                        )}
                                                    </button>
                                                )}
                                                {props.hasPermission('perm_btn_return') && (
                                                    <button 
                                                        onClick={() => props.onToggleTask(task.id)} 
                                                        className="w-14 h-14 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-orange-600 hover:bg-orange-500 text-white shadow-md transition-all active:scale-95 border border-orange-500" 
                                                        title={t('btn_stop')}
                                                    >
                                                        <ReturnIcon className="w-8 h-8 sm:w-9 sm:h-9" />
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* RIGHT FIXED COLUMN: Secondary Actions (Fixed width) */}
                        <div className="flex flex-col w-12 sm:w-14 border-l border-white/10 bg-black/30 shrink-0">
                             {props.hasPermission('perm_btn_note') && (
                                <button onClick={() => handleNoteClick(task)} className={`flex-1 flex items-center justify-center transition-colors ${task.note ? 'text-yellow-400 bg-yellow-900/20' : 'text-gray-400 hover:text-white hover:bg-white/5'}`} title={t('btn_note')}>
                                    <ChatIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                             {props.hasPermission('perm_btn_edit') && !task.isDone && (
                                <button onClick={() => startEditing(task)} className="flex-1 flex items-center justify-center text-blue-400 hover:text-blue-300 hover:bg-white/5 border-t border-white/5 transition-colors" title={t('perm_btn_edit')}>
                                    <EditIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                             {props.hasPermission('perm_btn_incorrect') && task.status !== 'incorrectly_entered' && (
                                <button onClick={() => { if(window.confirm(t('incorrect_confirm'))) props.onMarkAsIncorrect(task.id); }} className="flex-1 flex items-center justify-center text-orange-500 hover:text-orange-400 hover:bg-white/5 border-t border-white/5 transition-colors" title={t('btn_mark_incorrect')}>
                                    <XMarkIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                             {props.hasPermission('perm_btn_delete') && (
                                <button onClick={() => { if(window.confirm(t('miss_delete_confirm'))) props.onDeleteTask(task.id); }} className="flex-1 flex items-center justify-center text-red-500 hover:text-red-400 hover:bg-white/5 border-t border-white/5 transition-colors" title={t('perm_btn_delete')}>
                                    <TrashIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </button>
                             )}
                        </div>

                        {/* Note Modal Overlay (Still inline for now) */}
                        {showNoteInput && (
                            <div className="absolute inset-0 bg-gray-900/95 z-20 flex flex-col justify-center p-4">
                                <div className="space-y-2">
                                    <h4 className="text-yellow-400 font-bold mb-2">{t('btn_note')}</h4>
                                    <textarea 
                                        value={noteVal} 
                                        onChange={(e) => setNoteVal(e.target.value)} 
                                        className="w-full bg-gray-800 text-white p-3 rounded-lg border border-gray-600 focus:border-yellow-500 outline-none" 
                                        rows={3}
                                        autoFocus
                                    />
                                    <div className="flex gap-2">
                                        <button onClick={() => saveNote(task.id)} className="flex-1 bg-yellow-600 hover:bg-yellow-500 text-white py-3 rounded-lg font-bold transition-colors">{t('btn_save')}</button>
                                        <button onClick={() => setNoteId(null)} className="flex-1 bg-gray-800 hover:bg-gray-700 text-gray-400 py-3 rounded-lg font-bold transition-colors">{t('btn_cancel')}</button>
                                    </div>
                                </div>
                            </div>
                        )}

                    </div>
                );
            })}

            {/* Global Modal for Missing Reason - Rendered via Portal to escape transforms */}
            {missingId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setMissingId(null)}>
                    <div className="bg-gray-800 border-2 border-red-600 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold text-red-400 mb-6 text-center uppercase tracking-wide">{t('modal_missing_title')}</h3>
                        <div className="grid grid-cols-1 gap-3">
                            {props.missingReasons.map(r => (
                                <button 
                                    key={r.id} 
                                    onClick={() => confirmMissing(missingId, r.value)} 
                                    className="p-4 bg-gray-700 hover:bg-red-900/30 border border-gray-600 hover:border-red-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1"
                                >
                                    {r.value}
                                </button>
                            ))}
                        </div>
                        <button 
                            onClick={() => setMissingId(null)} 
                            className="w-full mt-6 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors"
                        >
                            {t('btn_cancel')}
                        </button>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default TaskList;

import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit,
  setDoc
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons as seedMissingReasons } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean;
  inventoryHistory?: InventorySession[];
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Sound logic refs to avoid re-subscribing listeners
  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  // Sync refs
  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // Helper function using refs for use inside listeners
  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = rolesRef.current.find(r => r.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- INITIALIZATION ---

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = roles.find(r => r.name === currentUserRole);
      if (!r) return false;
      return permissions.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- DATA FETCHING ---

  // Users - Realtime (Important for login check)
  useEffect(() => {
    const q = query(collection(db, 'users'));
    return onSnapshot(q, (snapshot) => {
        const fetchedUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserData));
        if (fetchedUsers.length === 0) seedDatabase(); 
        else setUsers(fetchedUsers);
    });
  }, []);

  // Tasks - Realtime (CRITICAL OPTIMIZATION: Empty dependency array)
  useEffect(() => {
    // OPTIMIZATION: In a real app, you might want to limit this query (e.g. limit(500) or where('isDone', '==', false))
    const q = query(collection(db, 'tasks')); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      // Sound Notification Logic - uses checkPermissionRef to avoid re-render loop
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      // Sort Logic
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    });
  }, []); // REMOVED dependencies to prevent re-fetching on role change

  // --- STATIC DATA OPTIMIZATION: Use getDocs instead of onSnapshot ---
  // Helper to refresh static data
  const refreshParts = async () => { const s = await getDocs(query(collection(db, 'parts'), orderBy('value'))); setParts(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))); };
  const refreshWorkplaces = async () => { const s = await getDocs(query(collection(db, 'workplaces'), orderBy('value'))); setWorkplaces(s.docs.map(d => ({id:d.id, value:d.data().value, standardTime:d.data().standardTime} as DBItem))); };
  const refreshMissingReasons = async () => { const s = await getDocs(query(collection(db, 'missing_reasons'), orderBy('value'))); setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))); };
  const refreshBOM = async () => { const s = await getDocs(query(collection(db, 'bom_items'))); setBomItems(s.docs.map(d => ({id:d.id, ...d.data()} as BOMItem))); };

  // Initial Fetch for static data
  useEffect(() => { refreshParts(); }, []);
  useEffect(() => { refreshWorkplaces(); }, []);
  useEffect(() => { refreshMissingReasons(); }, []);
  useEffect(() => { refreshBOM(); }, []);

  // Realtime needed for Requests & Breaks & Roles (Admin/Mgmt stuff)
  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'break_schedules')); return onSnapshot(q, s => setBreakSchedules(s.docs.map(d => ({id:d.id, ...d.data()} as BreakSchedule)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'notifications')); return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); }, []);

  // System breaks needs to be realtime for calculations
  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
          setIsBreakActive(breaks.some(b => b.isActive));
      }); 
  }, []);

  // Roles & Permissions (Keep realtime to update UI instantly)
  useEffect(() => {
      const q = query(collection(db, 'roles'));
      return onSnapshot(q, (snapshot) => {
          const fetchedRoles = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Role));
          if (fetchedRoles.length === 0) seedRolesAndPermissions();
          else setRoles(fetchedRoles);
      });
  }, []);
  useEffect(() => {
      const q = query(collection(db, 'permissions'));
      return onSnapshot(q, (snapshot) => {
          setPermissions(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Permission)));
      });
  }, []);

  // Break Logic
  useEffect(() => {
      if (!breakSchedules.length) return;
      const checkTime = () => {
          const now = new Date();
          const hours = String(now.getHours()).padStart(2, '0');
          const minutes = String(now.getMinutes()).padStart(2, '0');
          const currentHM = `${hours}:${minutes}`;

          const matchingSchedule = breakSchedules.find(s => currentHM >= s.start && currentHM < s.end);
          if (matchingSchedule && !isBreakActive) {
              const recentlyCreated = systemBreaks.some(sb => sb.isActive && Math.abs(sb.start - Date.now()) < 60000);
              if (!recentlyCreated) addDoc(collection(db, 'system_breaks'), { start: Date.now(), isActive: true });
          }

          const matchingEnd = breakSchedules.find(s => s.end === currentHM);
          const isInsideAnySchedule = breakSchedules.some(s => currentHM >= s.start && currentHM < s.end);
          if ((matchingEnd || !isInsideAnySchedule) && isBreakActive) {
              const activeBreak = systemBreaks.find(b => b.isActive);
              if (activeBreak) updateDoc(doc(db, 'system_breaks', activeBreak.id), { end: Date.now(), isActive: false });
          }
      };
      const interval = setInterval(checkTime, 10000); 
      return () => clearInterval(interval);
  }, [breakSchedules, isBreakActive, systemBreaks]);

  const seedDatabase = async () => {
      await addDoc(collection(db, 'users'), { username: 'USER', password: '123', role: 'USER' });
      await addDoc(collection(db, 'users'), { username: 'ADMIN', password: '321', role: 'ADMIN' });
      const b = writeBatch(db);
      initialParts.forEach(p => b.set(doc(collection(db, 'parts')), { value: p }));
      initialWorkplaces.forEach(w => b.set(doc(collection(db, 'workplaces')), { value: w }));
      seedMissingReasons.forEach(r => b.set(doc(collection(db, 'missing_reasons')), { value: r }));
      await b.commit();
      refreshParts(); refreshWorkplaces(); refreshMissingReasons(); // Manual refresh after seed
  };

  const seedRolesAndPermissions = async () => {
      const batch = writeBatch(db);
      const roleDefs = [
          { name: 'ADMIN', isSystem: true },
          { name: 'USER', isSystem: true },
          { name: 'LEADER', isSystem: true }
      ];
      const roleMap: Record<string, string> = {};

      for (const r of roleDefs) {
          const ref = doc(db, 'roles', r.name); 
          batch.set(ref, r);
          roleMap[r.name] = ref.id;
      }

      const allPerms = [
          'perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_missing', 'perm_tab_permissions',
          'perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_cancel_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_return', 'perm_btn_lock',
          'perm_view_fullscreen', 'perm_play_sound', 'perm_view_passwords',
          'perm_manage_users', 'perm_manage_db', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'
      ];

      const assign = (role: string, list: string[]) => {
          const rid = roleMap[role];
          if (!rid) return;
          list.forEach(p => batch.set(doc(collection(db, 'permissions')), { roleId: rid, permissionName: p }));
      };

      assign('ADMIN', allPerms);
      assign('USER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_finish', 'perm_play_sound']);
      assign('LEADER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_incorrect', 'perm_btn_edit', 'perm_btn_return', 'perm_play_sound']); 

      await batch.commit();
  };

  // --- ACTIONS ---

  const handleLogin = (u: string, r: any) => { setIsAuthenticated(true); setCurrentUser(u); setCurrentUserRole(r); localStorage.setItem('app_user', u); localStorage.setItem('app_role', r); };
  const handleLogout = () => { setIsAuthenticated(false); setCurrentUser(''); setCurrentUserRole('USER'); localStorage.removeItem('app_user'); localStorage.removeItem('app_role'); };
  const handleAddUser = (u: UserData) => addDoc(collection(db, 'users'), u);
  const handleUpdatePassword = (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {password: p}); };
  const handleUpdateUserRole = (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {role: r}); };
  const handleDeleteUser = (u: string) => { const user = users.find(us => us.username === u); if(user) deleteDoc(doc(db,'users', user.id!)); };

  const handleAddPart = async (v: string) => { await addDoc(collection(db,'parts'), {value:v}); refreshParts(); };
  const handleBatchAddParts = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(v => b.set(doc(collection(db,'parts')), {value:v})); await b.commit(); refreshParts(); };
  const handleDeletePart = async (id: string) => { await deleteDoc(doc(db,'parts',id)); refreshParts(); };
  const handleDeleteAllParts = async () => { const s=await getDocs(collection(db,'parts')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshParts(); };

  const handleAddWorkplace = async (v: string, t?: number) => { await addDoc(collection(db,'workplaces'), {value:v, standardTime:t||0}); refreshWorkplaces(); };
  const handleBatchAddWorkplaces = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0})}); await b.commit(); refreshWorkplaces(); };
  const handleDeleteWorkplace = async (id: string) => { await deleteDoc(doc(db,'workplaces',id)); refreshWorkplaces(); };
  const handleDeleteAllWorkplaces = async () => { const s=await getDocs(collection(db,'workplaces')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshWorkplaces(); };

  const handleAddMissingReason = async (v: string) => { await addDoc(collection(db,'missing_reasons'), {value:v}); refreshMissingReasons(); };
  const handleDeleteMissingReason = async (id: string) => { await deleteDoc(doc(db,'missing_reasons',id)); refreshMissingReasons(); };
  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));

  const handleAddBreakSchedule = (s:string, e:string) => addDoc(collection(db,'break_schedules'), {start:s, end:e});
  const handleDeleteBreakSchedule = (id: string) => deleteDoc(doc(db,'break_schedules',id));

  const handleAddBOMItem = async (p:string, c:string, q:number) => { await addDoc(collection(db,'bom_items'), {parentPart:p, childPart:c, quantity:q}); refreshBOM(); };
  const handleBatchAddBOMItems = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const p=l.split(';'); if(p.length>=3) b.set(doc(collection(db,'bom_items')), {parentPart:p[0].trim(), childPart:p[1].trim(), quantity:parseFloat(p[2].trim().replace(',','.'))})}); await b.commit(); refreshBOM(); };
  const handleDeleteBOMItem = async (id: string) => { await deleteDoc(doc(db,'bom_items',id)); refreshBOM(); };
  const handleDeleteAllBOMItems = async () => { const s=await getDocs(collection(db,'bom_items')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshBOM(); };
  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));

  const handleAddRole = (n:string) => addDoc(collection(db,'roles'), {name:n.toUpperCase(), isSystem:false});
  const handleDeleteRole = async (id:string) => { await deleteDoc(doc(db,'roles',id)); const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); b.commit(); };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { const r=roles.find(ro=>ro.name===rname); if(!r)return; if(has) addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) deleteDoc(doc(db,'permissions',p.id)); } };

  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel) => {
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(unit==='boxes') fQty=`${qty} box`; 
    if(unit==='pallet') fQty=`${qty} pal`;

    let text = `${formattedDate} / ${pn}`;
    if (wp) text += ` / ${wp}`;
    if (fQty) text += ` / Počet: ${fQty}`;

    const wpObj = workplaces.find(w => w.value === wp);
    await addDoc(collection(db, 'tasks'), { 
        text: text, 
        partNumber: pn, 
        workplace: wp, 
        quantity: qty, 
        quantityUnit: unit, 
        standardTime: wpObj?.standardTime||0, 
        isDone:false, 
        priority:prio, 
        createdAt:Date.now(), 
        createdBy:currentUser 
    });
  };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false });
    }
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));

  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null,
              // AUTO FINISH when marked as missing
              isDone: isMissing ? true : t.isDone,
              completedAt: isMissing ? Date.now() : t.completedAt,
              completedBy: isMissing ? currentUser : t.completedBy,
              isInProgress: false, // Ensure it's not in progress if marked missing
              inProgressBy: null,
              isBlocked: false // Ensure it's not blocked if marked missing
          });
          // Alert Notification
          if (isMissing) {
              await addDoc(collection(db, 'notifications'), {
                  partNumber: t.partNumber || 'Unknown',
                  reason: reason || 'Iné',
                  reportedBy: currentUser,
                  timestamp: Date.now()
              });
          }
      } 
  };

  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));

  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          updateDoc(doc(db,'tasks',id), { isBlocked, inventoryHistory:hist });
      }
  };

  const handleArchiveTasks = async () => {
      const q = query(collection(db,'tasks'), where('isDone','==',true), limit(1000));
      const s = await getDocs(q);
      const toArchive = s.docs.filter(d => !d.data().completedAt || d.data().completedAt < (Date.now() - 86400000));
      if(toArchive.length===0) return {success:true, count:0, message:"Žiadne staré úlohy."};
      const b=writeBatch(db);
      toArchive.forEach(d => { b.set(doc(collection(db,'archived_tasks')), {...d.data(), archivedAt:Date.now()}); b.delete(d.ref); });
      await b.commit();
      return {success:true, count:toArchive.length};
  };
  const fetchArchivedTasks = async () => (await getDocs(collection(db,'archived_tasks'))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onDeleteTask={handleDeleteTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={parts} workplaces={workplaces} missingReasons={missingReasons}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest}
          roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Role, Permission } from '../App'; 
import { useLanguage } from './LanguageContext';

interface PermissionsTabProps {
    roles: Role[];
    permissions: Permission[];
    onAddRole: (name: string) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
}

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, permissions, onAddRole, onDeleteRole, onUpdatePermission }) => {
    const { t } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');

    const permGroups = [
      {
          name: 'perm_group_tabs',
          perms: ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_missing', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_permissions'] 
      },
      {
          name: 'perm_group_actions',
          perms: ['perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_cancel_missing', 'perm_btn_copy', 'perm_btn_return', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_lock', 'perm_view_fullscreen', 'perm_play_sound', 'perm_push_notification', 'perm_view_passwords']
      },
      {
          name: 'perm_group_mgmt',
          perms: ['perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'] 
      }
    ];

    const handleAddRole = (e: React.FormEvent) => {
      e.preventDefault();
      if (newRoleName.trim()) {
          onAddRole(newRoleName.trim());
          setNewRoleName('');
      }
    };

    const hasPermission = (roleId: string, permName: string) => {
        return permissions?.some(p => p.roleId === roleId && p.permissionName === permName) || false;
    };

    // Sort roles: System roles first, then custom roles alphabetically
    const sortedRoles = [...roles].sort((a, b) => {
        if (a.isSystem && !b.isSystem) return -1;
        if (!a.isSystem && b.isSystem) return 1;
        return a.name.localeCompare(b.name);
    });

    const handleDeleteClick = (e: React.MouseEvent, role: Role) => {
        e.preventDefault();
        e.stopPropagation();
        if (window.confirm(t('role_delete_confirm'))) {
            onDeleteRole(role.id);
        }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 pb-8 animate-fade-in">
            <h1 className="text-center text-2xl sm:text-3xl font-bold text-orange-400 mb-6 sm:mb-8">{t('sect_roles')}</h1>

            {permGroups.map(group => (
                 <div key={group.name} className="bg-gray-900 rounded-xl p-6 shadow-lg border border-gray-700">
                     <h3 className="text-lg font-bold text-gray-300 mb-4 border-b border-gray-700 pb-2">{t(group.name as any)}</h3>
                     <div className="overflow-x-auto custom-scrollbar"> 
                         <table className="min-w-[600px] w-full text-left text-sm border-collapse">
                             <thead>
                                 <tr className="border-b-2 border-gray-700">
                                     <th className="py-3 px-4 text-gray-400 font-semibold w-1/3 min-w-[200px]">{t('permission_label')}</th> 
                                     {sortedRoles.map(role => (
                                         <th key={role.id} className="py-3 px-4 text-white font-bold text-center">
                                             <div className="flex items-center justify-center gap-1">
                                                 {role.name}
                                                 {role.name !== 'ADMIN' && (
                                                     <button 
                                                         type="button"
                                                         onClick={(e) => handleDeleteClick(e, role)} 
                                                         className="ml-2 text-red-600 hover:text-red-400 transition-colors p-1 focus:outline-none"
                                                         title={t('perm_btn_delete')}
                                                     >
                                                         <TrashIcon className="w-4 h-4" />
                                                     </button>
                                                 )}
                                             </div>
                                         </th>
                                     ))}
                                 </tr>
                             </thead>
                             <tbody>
                                 {group.perms.map(perm => (
                                     <tr key={perm} className="border-b border-gray-800 hover:bg-gray-800/50">
                                         <td className="py-3 px-4 text-gray-300">{t(perm as any)}</td>
                                         {sortedRoles.map(role => (
                                             <td key={`${role.id}-${perm}`} className="py-3 px-4 text-center">
                                                 <input 
                                                     type="checkbox" 
                                                     checked={hasPermission(role.id, perm)} 
                                                     onChange={(e) => onUpdatePermission(perm, role.name, e.target.checked)}
                                                     className="w-5 h-5 text-orange-500 bg-gray-700 border-gray-600 rounded focus:ring-orange-500 focus:ring-2" 
                                                 />
                                             </td>
                                         ))}
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                     </div>
                 </div>
             ))}

            <div className="bg-gray-900 rounded-xl p-6 shadow-lg border border-gray-700">
                 <h3 className="text-lg font-bold text-gray-300 mb-4">{t('role_add_new_title')}</h3> 
                 <form onSubmit={handleAddRole} className="flex flex-col sm:flex-row gap-2 max-w-sm mt-4">
                     <input value={newRoleName} onChange={e => setNewRoleName(e.target.value)} placeholder={t('role_name_place')} className="flex-1 bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white text-sm uppercase" />
                     <button type="submit" className="bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded font-semibold">{t('role_add_btn')}</button>
                 </form>
             </div>
        </div>
    );
};

export default PermissionsTab;

import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit,
  setDoc
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons as seedMissingReasons } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean;
  inventoryHistory?: InventorySession[];
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Sound logic refs to avoid re-subscribing listeners
  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  // Sync refs
  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // Helper function using refs for use inside listeners
  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = rolesRef.current.find(r => r.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- INITIALIZATION ---

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = roles.find(r => r.name === currentUserRole);
      if (!r) return false;
      return permissions.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- DATA FETCHING ---

  // Users - Realtime (Important for login check)
  useEffect(() => {
    const q = query(collection(db, 'users'));
    return onSnapshot(q, (snapshot) => {
        const fetchedUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserData));
        if (fetchedUsers.length === 0) seedDatabase(); 
        else setUsers(fetchedUsers);
    });
  }, []);

  // Tasks - Realtime (CRITICAL OPTIMIZATION: Empty dependency array)
  useEffect(() => {
    // OPTIMIZATION: In a real app, you might want to limit this query (e.g. limit(500) or where('isDone', '==', false))
    const q = query(collection(db, 'tasks')); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      // Sound Notification Logic - uses checkPermissionRef to avoid re-render loop
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      // Sort Logic
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    });
  }, []); // REMOVED dependencies to prevent re-fetching on role change

  // --- STATIC DATA OPTIMIZATION: Use getDocs instead of onSnapshot ---
  // Helper to refresh static data
  const refreshParts = async () => { const s = await getDocs(query(collection(db, 'parts'), orderBy('value'))); setParts(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))); };
  const refreshWorkplaces = async () => { const s = await getDocs(query(collection(db, 'workplaces'), orderBy('value'))); setWorkplaces(s.docs.map(d => ({id:d.id, value:d.data().value, standardTime:d.data().standardTime} as DBItem))); };
  const refreshMissingReasons = async () => { const s = await getDocs(query(collection(db, 'missing_reasons'), orderBy('value'))); setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))); };
  const refreshBOM = async () => { const s = await getDocs(query(collection(db, 'bom_items'))); setBomItems(s.docs.map(d => ({id:d.id, ...d.data()} as BOMItem))); };

  // Initial Fetch for static data
  useEffect(() => { refreshParts(); }, []);
  useEffect(() => { refreshWorkplaces(); }, []);
  useEffect(() => { refreshMissingReasons(); }, []);
  useEffect(() => { refreshBOM(); }, []);

  // Realtime needed for Requests & Breaks & Roles (Admin/Mgmt stuff)
  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'break_schedules')); return onSnapshot(q, s => setBreakSchedules(s.docs.map(d => ({id:d.id, ...d.data()} as BreakSchedule)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'notifications')); return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); }, []);

  // System breaks needs to be realtime for calculations
  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
          setIsBreakActive(breaks.some(b => b.isActive));
      }); 
  }, []);

  // Roles & Permissions (Keep realtime to update UI instantly)
  useEffect(() => {
      const q = query(collection(db, 'roles'));
      return onSnapshot(q, (snapshot) => {
          const fetchedRoles = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Role));

          // AUTO-CLEANUP: Delete legacy roles if they exist in DB
          const legacyRoles = ['SUPERVISOR', 'LOGISTICIAN'];
          fetchedRoles.forEach(role => {
              if (legacyRoles.includes(role.name.toUpperCase())) {
                  // Delete role doc
                  deleteDoc(doc(db, 'roles', role.id));
                  // Delete permissions for this role
                  getDocs(query(collection(db, 'permissions'), where('roleId', '==', role.id)))
                    .then(permSnap => {
                        const batch = writeBatch(db);
                        permSnap.forEach(p => batch.delete(p.ref));
                        batch.commit();
                    });
              }
          });

          // Filter out legacy roles from state immediately for better UX
          const validRoles = fetchedRoles.filter(r => !legacyRoles.includes(r.name.toUpperCase()));

          if (validRoles.length === 0 && fetchedRoles.length === 0) seedRolesAndPermissions();
          else setRoles(validRoles);
      });
  }, []);

  useEffect(() => {
      const q = query(collection(db, 'permissions'));
      return onSnapshot(q, (snapshot) => {
          setPermissions(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Permission)));
      });
  }, []);

  // Break Logic
  useEffect(() => {
      if (!breakSchedules.length) return;
      const checkTime = () => {
          const now = new Date();
          const hours = String(now.getHours()).padStart(2, '0');
          const minutes = String(now.getMinutes()).padStart(2, '0');
          const currentHM = `${hours}:${minutes}`;

          const matchingSchedule = breakSchedules.find(s => currentHM >= s.start && currentHM < s.end);
          if (matchingSchedule && !isBreakActive) {
              const recentlyCreated = systemBreaks.some(sb => sb.isActive && Math.abs(sb.start - Date.now()) < 60000);
              if (!recentlyCreated) addDoc(collection(db, 'system_breaks'), { start: Date.now(), isActive: true });
          }

          const matchingEnd = breakSchedules.find(s => s.end === currentHM);
          const isInsideAnySchedule = breakSchedules.some(s => currentHM >= s.start && currentHM < s.end);
          if ((matchingEnd || !isInsideAnySchedule) && isBreakActive) {
              const activeBreak = systemBreaks.find(b => b.isActive);
              if (activeBreak) updateDoc(doc(db, 'system_breaks', activeBreak.id), { end: Date.now(), isActive: false });
          }
      };
      const interval = setInterval(checkTime, 10000); 
      return () => clearInterval(interval);
  }, [breakSchedules, isBreakActive, systemBreaks]);

  const seedDatabase = async () => {
      await addDoc(collection(db, 'users'), { username: 'USER', password: '123', role: 'USER' });
      await addDoc(collection(db, 'users'), { username: 'ADMIN', password: '321', role: 'ADMIN' });
      const b = writeBatch(db);
      initialParts.forEach(p => b.set(doc(collection(db, 'parts')), { value: p }));
      initialWorkplaces.forEach(w => b.set(doc(collection(db, 'workplaces')), { value: w }));
      seedMissingReasons.forEach(r => b.set(doc(collection(db, 'missing_reasons')), { value: r }));
      await b.commit();
      refreshParts(); refreshWorkplaces(); refreshMissingReasons(); // Manual refresh after seed
  };

  const seedRolesAndPermissions = async () => {
      const batch = writeBatch(db);
      const roleDefs = [
          { name: 'ADMIN', isSystem: true },
          { name: 'USER', isSystem: true },
          { name: 'LEADER', isSystem: true }
      ];
      const roleMap: Record<string, string> = {};

      for (const r of roleDefs) {
          const ref = doc(db, 'roles', r.name); 
          batch.set(ref, r);
          roleMap[r.name] = ref.id;
      }

      const allPerms = [
          'perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_missing', 'perm_tab_permissions',
          'perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_cancel_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_return', 'perm_btn_lock',
          'perm_view_fullscreen', 'perm_play_sound', 'perm_view_passwords',
          'perm_manage_users', 'perm_manage_db', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'
      ];

      const assign = (role: string, list: string[]) => {
          const rid = roleMap[role];
          if (!rid) return;
          list.forEach(p => batch.set(doc(collection(db, 'permissions')), { roleId: rid, permissionName: p }));
      };

      assign('ADMIN', allPerms);
      assign('USER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_finish', 'perm_play_sound']);
      assign('LEADER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_incorrect', 'perm_btn_edit', 'perm_btn_return', 'perm_play_sound']); 

      await batch.commit();
  };

  // --- ACTIONS ---

  const handleLogin = (u: string, r: any) => { setIsAuthenticated(true); setCurrentUser(u); setCurrentUserRole(r); localStorage.setItem('app_user', u); localStorage.setItem('app_role', r); };
  const handleLogout = () => { setIsAuthenticated(false); setCurrentUser(''); setCurrentUserRole('USER'); localStorage.removeItem('app_user'); localStorage.removeItem('app_role'); };
  const handleAddUser = (u: UserData) => addDoc(collection(db, 'users'), u);
  const handleUpdatePassword = (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {password: p}); };
  const handleUpdateUserRole = (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {role: r}); };
  const handleDeleteUser = (u: string) => { const user = users.find(us => us.username === u); if(user) deleteDoc(doc(db,'users', user.id!)); };

  const handleAddPart = async (v: string) => { await addDoc(collection(db,'parts'), {value:v}); refreshParts(); };
  const handleBatchAddParts = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(v => b.set(doc(collection(db,'parts')), {value:v})); await b.commit(); refreshParts(); };
  const handleDeletePart = async (id: string) => { await deleteDoc(doc(db,'parts',id)); refreshParts(); };
  const handleDeleteAllParts = async () => { const s=await getDocs(collection(db,'parts')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshParts(); };

  const handleAddWorkplace = async (v: string, t?: number) => { await addDoc(collection(db,'workplaces'), {value:v, standardTime:t||0}); refreshWorkplaces(); };
  const handleBatchAddWorkplaces = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0})}); await b.commit(); refreshWorkplaces(); };
  const handleDeleteWorkplace = async (id: string) => { await deleteDoc(doc(db,'workplaces',id)); refreshWorkplaces(); };
  const handleDeleteAllWorkplaces = async () => { const s=await getDocs(collection(db,'workplaces')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshWorkplaces(); };

  const handleAddMissingReason = async (v: string) => { await addDoc(collection(db,'missing_reasons'), {value:v}); refreshMissingReasons(); };
  const handleDeleteMissingReason = async (id: string) => { await deleteDoc(doc(db,'missing_reasons',id)); refreshMissingReasons(); };
  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));

  const handleAddBreakSchedule = (s:string, e:string) => addDoc(collection(db,'break_schedules'), {start:s, end:e});
  const handleDeleteBreakSchedule = (id: string) => deleteDoc(doc(db,'break_schedules',id));

  const handleAddBOMItem = async (p:string, c:string, q:number) => { await addDoc(collection(db,'bom_items'), {parentPart:p, childPart:c, quantity:q}); refreshBOM(); };
  const handleBatchAddBOMItems = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const p=l.split(';'); if(p.length>=3) b.set(doc(collection(db,'bom_items')), {parentPart:p[0].trim(), childPart:p[1].trim(), quantity:parseFloat(p[2].trim().replace(',','.'))})}); await b.commit(); refreshBOM(); };
  const handleDeleteBOMItem = async (id: string) => { await deleteDoc(doc(db,'bom_items',id)); refreshBOM(); };
  const handleDeleteAllBOMItems = async () => { const s=await getDocs(collection(db,'bom_items')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshBOM(); };
  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));

  const handleAddRole = (n:string) => addDoc(collection(db,'roles'), {name:n.toUpperCase(), isSystem:false});
  const handleDeleteRole = async (id:string) => { await deleteDoc(doc(db,'roles',id)); const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); b.commit(); };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { const r=roles.find(ro=>ro.name===rname); if(!r)return; if(has) addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) deleteDoc(doc(db,'permissions',p.id)); } };

  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel) => {
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(unit==='boxes') fQty=`${qty} box`; 
    if(unit==='pallet') fQty=`${qty} pal`;

    let text = `${formattedDate} / ${pn}`;
    if (wp) text += ` / ${wp}`;
    if (fQty) text += ` / Počet: ${fQty}`;

    const wpObj = workplaces.find(w => w.value === wp);
    await addDoc(collection(db, 'tasks'), { 
        text: text, 
        partNumber: pn, 
        workplace: wp, 
        quantity: qty, 
        quantityUnit: unit, 
        standardTime: wpObj?.standardTime||0, 
        isDone:false, 
        priority:prio, 
        createdAt:Date.now(), 
        createdBy:currentUser 
    });
  };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false });
    }
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));

  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null,
              // AUTO FINISH when marked as missing
              isDone: isMissing ? true : t.isDone,
              completedAt: isMissing ? Date.now() : t.completedAt,
              completedBy: isMissing ? currentUser : t.completedBy,
              isInProgress: false, // Ensure it's not in progress if marked missing
              inProgressBy: null,
              isBlocked: false // Ensure it's not blocked if marked missing
          });
          // Alert Notification
          if (isMissing) {
              await addDoc(collection(db, 'notifications'), {
                  partNumber: t.partNumber || 'Unknown',
                  reason: reason || 'Iné',
                  reportedBy: currentUser,
                  timestamp: Date.now()
              });
          }
      } 
  };

  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));

  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          updateDoc(doc(db,'tasks',id), { isBlocked, inventoryHistory:hist });
      }
  };

  const handleArchiveTasks = async () => {
      const q = query(collection(db,'tasks'), where('isDone','==',true), limit(1000));
      const s = await getDocs(q);
      const toArchive = s.docs.filter(d => !d.data().completedAt || d.data().completedAt < (Date.now() - 86400000));
      if(toArchive.length===0) return {success:true, count:0, message:"Žiadne staré úlohy."};
      const b=writeBatch(db);
      toArchive.forEach(d => { b.set(doc(collection(db,'archived_tasks')), {...d.data(), archivedAt:Date.now()}); b.delete(d.ref); });
      await b.commit();
      return {success:true, count:toArchive.length};
  };
  const fetchArchivedTasks = async () => (await getDocs(collection(db,'archived_tasks'))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onDeleteTask={handleDeleteTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={parts} workplaces={workplaces} missingReasons={missingReasons}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest}
          roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit,
  setDoc
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons as seedMissingReasons } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean;
  inventoryHistory?: InventorySession[];
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Sound logic refs to avoid re-subscribing listeners
  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  // Sync refs
  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // Helper function using refs for use inside listeners
  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = rolesRef.current.find(r => r.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- INITIALIZATION ---

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = roles.find(r => r.name === currentUserRole);
      if (!r) return false;
      return permissions.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- DATA FETCHING ---

  // Users - Realtime (Important for login check)
  useEffect(() => {
    const q = query(collection(db, 'users'));
    return onSnapshot(q, (snapshot) => {
        const fetchedUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserData));
        if (fetchedUsers.length === 0) seedDatabase(); 
        else setUsers(fetchedUsers);
    });
  }, []);

  // Tasks - Realtime (CRITICAL OPTIMIZATION: Empty dependency array)
  useEffect(() => {
    // OPTIMIZATION: In a real app, you might want to limit this query (e.g. limit(500) or where('isDone', '==', false))
    const q = query(collection(db, 'tasks')); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      // Sound Notification Logic - uses checkPermissionRef to avoid re-render loop
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      // Sort Logic
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    });
  }, []); // REMOVED dependencies to prevent re-fetching on role change

  // --- STATIC DATA OPTIMIZATION: Use getDocs instead of onSnapshot ---
  // Helper to refresh static data
  const refreshParts = async () => { const s = await getDocs(query(collection(db, 'parts'), orderBy('value'))); setParts(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))); };
  const refreshWorkplaces = async () => { const s = await getDocs(query(collection(db, 'workplaces'), orderBy('value'))); setWorkplaces(s.docs.map(d => ({id:d.id, value:d.data().value, standardTime:d.data().standardTime} as DBItem))); };
  const refreshMissingReasons = async () => { const s = await getDocs(query(collection(db, 'missing_reasons'), orderBy('value'))); setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))); };
  const refreshBOM = async () => { const s = await getDocs(query(collection(db, 'bom_items'))); setBomItems(s.docs.map(d => ({id:d.id, ...d.data()} as BOMItem))); };

  // Initial Fetch for static data
  useEffect(() => { refreshParts(); }, []);
  useEffect(() => { refreshWorkplaces(); }, []);
  useEffect(() => { refreshMissingReasons(); }, []);
  useEffect(() => { refreshBOM(); }, []);

  // Realtime needed for Requests & Breaks & Roles (Admin/Mgmt stuff)
  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'break_schedules')); return onSnapshot(q, s => setBreakSchedules(s.docs.map(d => ({id:d.id, ...d.data()} as BreakSchedule)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'notifications')); return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); }, []);

  // System breaks needs to be realtime for calculations
  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
          setIsBreakActive(breaks.some(b => b.isActive));
      }); 
  }, []);

  // Roles & Permissions (Keep realtime to update UI instantly)
  useEffect(() => {
      const q = query(collection(db, 'roles'));
      return onSnapshot(q, (snapshot) => {
          const fetchedRoles = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Role));

          const legacyRoles = ['SUPERVISOR', 'LOGISTICIAN'];
          const uniqueRolesMap = new Map<string, Role>();
          const toDeleteIds: string[] = [];

          // 1. Identify duplicates and legacy roles
          fetchedRoles.forEach(role => {
              const name = role.name.toUpperCase();

              if (legacyRoles.includes(name)) {
                  toDeleteIds.push(role.id);
                  return;
              }

              if (uniqueRolesMap.has(name)) {
                  const existing = uniqueRolesMap.get(name)!;
                  // Prefer system roles, or keep the existing one
                  if (existing.isSystem && !role.isSystem) {
                      toDeleteIds.push(role.id);
                  } else if (!existing.isSystem && role.isSystem) {
                      toDeleteIds.push(existing.id);
                      uniqueRolesMap.set(name, role);
                  } else {
                      // Duplicate of same type, delete current
                      toDeleteIds.push(role.id);
                  }
              } else {
                  uniqueRolesMap.set(name, role);
              }
          });

          // 2. Cleanup Duplicates in DB
          if (toDeleteIds.length > 0) {
              const batch = writeBatch(db);
              toDeleteIds.forEach(id => {
                  batch.delete(doc(db, 'roles', id));
              });
              batch.commit().catch(e => console.error("Error cleaning duplicates", e));
          }

          const validRoles = Array.from(uniqueRolesMap.values());

          if (validRoles.length === 0 && fetchedRoles.length === 0) seedRolesAndPermissions();
          else setRoles(validRoles);
      });
  }, []);

  useEffect(() => {
      const q = query(collection(db, 'permissions'));
      return onSnapshot(q, (snapshot) => {
          setPermissions(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Permission)));
      });
  }, []);

  // Break Logic
  useEffect(() => {
      if (!breakSchedules.length) return;
      const checkTime = () => {
          const now = new Date();
          const hours = String(now.getHours()).padStart(2, '0');
          const minutes = String(now.getMinutes()).padStart(2, '0');
          const currentHM = `${hours}:${minutes}`;

          const matchingSchedule = breakSchedules.find(s => currentHM >= s.start && currentHM < s.end);
          if (matchingSchedule && !isBreakActive) {
              const recentlyCreated = systemBreaks.some(sb => sb.isActive && Math.abs(sb.start - Date.now()) < 60000);
              if (!recentlyCreated) addDoc(collection(db, 'system_breaks'), { start: Date.now(), isActive: true });
          }

          const matchingEnd = breakSchedules.find(s => s.end === currentHM);
          const isInsideAnySchedule = breakSchedules.some(s => currentHM >= s.start && currentHM < s.end);
          if ((matchingEnd || !isInsideAnySchedule) && isBreakActive) {
              const activeBreak = systemBreaks.find(b => b.isActive);
              if (activeBreak) updateDoc(doc(db, 'system_breaks', activeBreak.id), { end: Date.now(), isActive: false });
          }
      };
      const interval = setInterval(checkTime, 10000); 
      return () => clearInterval(interval);
  }, [breakSchedules, isBreakActive, systemBreaks]);

  const seedDatabase = async () => {
      await addDoc(collection(db, 'users'), { username: 'USER', password: '123', role: 'USER' });
      await addDoc(collection(db, 'users'), { username: 'ADMIN', password: '321', role: 'ADMIN' });
      const b = writeBatch(db);
      initialParts.forEach(p => b.set(doc(collection(db, 'parts')), { value: p }));
      initialWorkplaces.forEach(w => b.set(doc(collection(db, 'workplaces')), { value: w }));
      seedMissingReasons.forEach(r => b.set(doc(collection(db, 'missing_reasons')), { value: r }));
      await b.commit();
      refreshParts(); refreshWorkplaces(); refreshMissingReasons(); // Manual refresh after seed
  };

  const seedRolesAndPermissions = async () => {
      const batch = writeBatch(db);
      const roleDefs = [
          { name: 'ADMIN', isSystem: true },
          { name: 'USER', isSystem: true },
          { name: 'LEADER', isSystem: true }
      ];
      const roleMap: Record<string, string> = {};

      for (const r of roleDefs) {
          const ref = doc(db, 'roles', r.name); 
          batch.set(ref, r);
          roleMap[r.name] = ref.id;
      }

      const allPerms = [
          'perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_missing', 'perm_tab_permissions',
          'perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_cancel_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_return', 'perm_btn_lock',
          'perm_view_fullscreen', 'perm_play_sound', 'perm_view_passwords',
          'perm_manage_users', 'perm_manage_db', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'
      ];

      const assign = (role: string, list: string[]) => {
          const rid = roleMap[role];
          if (!rid) return;
          list.forEach(p => batch.set(doc(collection(db, 'permissions')), { roleId: rid, permissionName: p }));
      };

      assign('ADMIN', allPerms);
      assign('USER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_finish', 'perm_play_sound']);
      assign('LEADER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_incorrect', 'perm_btn_edit', 'perm_btn_return', 'perm_play_sound']); 

      await batch.commit();
  };

  // --- ACTIONS ---

  const handleLogin = (u: string, r: any) => { setIsAuthenticated(true); setCurrentUser(u); setCurrentUserRole(r); localStorage.setItem('app_user', u); localStorage.setItem('app_role', r); };
  const handleLogout = () => { setIsAuthenticated(false); setCurrentUser(''); setCurrentUserRole('USER'); localStorage.removeItem('app_user'); localStorage.removeItem('app_role'); };
  const handleAddUser = (u: UserData) => addDoc(collection(db, 'users'), u);
  const handleUpdatePassword = (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {password: p}); };
  const handleUpdateUserRole = (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {role: r}); };
  const handleDeleteUser = (u: string) => { const user = users.find(us => us.username === u); if(user) deleteDoc(doc(db,'users', user.id!)); };

  const handleAddPart = async (v: string) => { await addDoc(collection(db,'parts'), {value:v}); refreshParts(); };
  const handleBatchAddParts = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(v => b.set(doc(collection(db,'parts')), {value:v})); await b.commit(); refreshParts(); };
  const handleDeletePart = async (id: string) => { await deleteDoc(doc(db,'parts',id)); refreshParts(); };
  const handleDeleteAllParts = async () => { const s=await getDocs(collection(db,'parts')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshParts(); };

  const handleAddWorkplace = async (v: string, t?: number) => { await addDoc(collection(db,'workplaces'), {value:v, standardTime:t||0}); refreshWorkplaces(); };
  const handleBatchAddWorkplaces = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0})}); await b.commit(); refreshWorkplaces(); };
  const handleDeleteWorkplace = async (id: string) => { await deleteDoc(doc(db,'workplaces',id)); refreshWorkplaces(); };
  const handleDeleteAllWorkplaces = async () => { const s=await getDocs(collection(db,'workplaces')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshWorkplaces(); };

  const handleAddMissingReason = async (v: string) => { await addDoc(collection(db,'missing_reasons'), {value:v}); refreshMissingReasons(); };
  const handleDeleteMissingReason = async (id: string) => { await deleteDoc(doc(db,'missing_reasons',id)); refreshMissingReasons(); };
  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));

  const handleAddBreakSchedule = (s:string, e:string) => addDoc(collection(db,'break_schedules'), {start:s, end:e});
  const handleDeleteBreakSchedule = (id: string) => deleteDoc(doc(db,'break_schedules',id));

  const handleAddBOMItem = async (p:string, c:string, q:number) => { await addDoc(collection(db,'bom_items'), {parentPart:p, childPart:c, quantity:q}); refreshBOM(); };
  const handleBatchAddBOMItems = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const p=l.split(';'); if(p.length>=3) b.set(doc(collection(db,'bom_items')), {parentPart:p[0].trim(), childPart:p[1].trim(), quantity:parseFloat(p[2].trim().replace(',','.'))})}); await b.commit(); refreshBOM(); };
  const handleDeleteBOMItem = async (id: string) => { await deleteDoc(doc(db,'bom_items',id)); refreshBOM(); };
  const handleDeleteAllBOMItems = async () => { const s=await getDocs(collection(db,'bom_items')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshBOM(); };
  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));

  const handleAddRole = (n:string) => {
      const nameUpper = n.toUpperCase();
      if (roles.some(r => r.name === nameUpper)) {
          alert("Rola s týmto názvom už existuje!");
          return;
      }
      addDoc(collection(db,'roles'), {name:nameUpper, isSystem:false});
  };
  const handleDeleteRole = async (id:string) => { await deleteDoc(doc(db,'roles',id)); const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); b.commit(); };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { const r=roles.find(ro=>ro.name===rname); if(!r)return; if(has) addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) deleteDoc(doc(db,'permissions',p.id)); } };

  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel) => {
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(unit==='boxes') fQty=`${qty} box`; 
    if(unit==='pallet') fQty=`${qty} pal`;

    let text = `${formattedDate} / ${pn}`;
    if (wp) text += ` / ${wp}`;
    if (fQty) text += ` / Počet: ${fQty}`;

    const wpObj = workplaces.find(w => w.value === wp);
    await addDoc(collection(db, 'tasks'), { 
        text: text, 
        partNumber: pn, 
        workplace: wp, 
        quantity: qty, 
        quantityUnit: unit, 
        standardTime: wpObj?.standardTime||0, 
        isDone:false, 
        priority:prio, 
        createdAt:Date.now(), 
        createdBy:currentUser 
    });
  };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false });
    }
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));

  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null,
              // AUTO FINISH when marked as missing
              isDone: isMissing ? true : t.isDone,
              completedAt: isMissing ? Date.now() : t.completedAt,
              completedBy: isMissing ? currentUser : t.completedBy,
              isInProgress: false, // Ensure it's not in progress if marked missing
              inProgressBy: null,
              isBlocked: false // Ensure it's not blocked if marked missing
          });
          // Alert Notification
          if (isMissing) {
              await addDoc(collection(db, 'notifications'), {
                  partNumber: t.partNumber || 'Unknown',
                  reason: reason || 'Iné',
                  reportedBy: currentUser,
                  timestamp: Date.now()
              });
          }
      } 
  };

  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));

  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          updateDoc(doc(db,'tasks',id), { isBlocked, inventoryHistory:hist });
      }
  };

  const handleArchiveTasks = async () => {
      const q = query(collection(db,'tasks'), where('isDone','==',true), limit(1000));
      const s = await getDocs(q);
      const toArchive = s.docs.filter(d => !d.data().completedAt || d.data().completedAt < (Date.now() - 86400000));
      if(toArchive.length===0) return {success:true, count:0, message:"Žiadne staré úlohy."};
      const b=writeBatch(db);
      toArchive.forEach(d => { b.set(doc(collection(db,'archived_tasks')), {...d.data(), archivedAt:Date.now()}); b.delete(d.ref); });
      await b.commit();
      return {success:true, count:toArchive.length};
  };
  const fetchArchivedTasks = async () => (await getDocs(collection(db,'archived_tasks'))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onDeleteTask={handleDeleteTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={parts} workplaces={workplaces} missingReasons={missingReasons}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest}
          roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit,
  setDoc
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons as seedMissingReasons } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean;
  inventoryHistory?: InventorySession[];
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Sound logic refs to avoid re-subscribing listeners
  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  // Sync refs
  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // Helper function using refs for use inside listeners
  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = rolesRef.current.find(r => r.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- INITIALIZATION ---

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = roles.find(r => r.name === currentUserRole);
      if (!r) return false;
      return permissions.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- DATA FETCHING ---

  // Users - Realtime (Important for login check)
  useEffect(() => {
    const q = query(collection(db, 'users'));
    return onSnapshot(q, (snapshot) => {
        const fetchedUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserData));
        if (fetchedUsers.length === 0) seedDatabase(); 
        else setUsers(fetchedUsers);
    });
  }, []);

  // Tasks - Realtime (CRITICAL OPTIMIZATION: Empty dependency array)
  useEffect(() => {
    // OPTIMIZATION: In a real app, you might want to limit this query (e.g. limit(500) or where('isDone', '==', false))
    const q = query(collection(db, 'tasks')); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      // Sound Notification Logic - uses checkPermissionRef to avoid re-render loop
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      // Sort Logic
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    });
  }, []); // REMOVED dependencies to prevent re-fetching on role change

  // --- STATIC DATA OPTIMIZATION: Use getDocs instead of onSnapshot ---
  // Helper to refresh static data
  const refreshParts = async () => { const s = await getDocs(query(collection(db, 'parts'), orderBy('value'))); setParts(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))); };
  const refreshWorkplaces = async () => { const s = await getDocs(query(collection(db, 'workplaces'), orderBy('value'))); setWorkplaces(s.docs.map(d => ({id:d.id, value:d.data().value, standardTime:d.data().standardTime} as DBItem))); };
  const refreshMissingReasons = async () => { const s = await getDocs(query(collection(db, 'missing_reasons'), orderBy('value'))); setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))); };
  const refreshBOM = async () => { const s = await getDocs(query(collection(db, 'bom_items'))); setBomItems(s.docs.map(d => ({id:d.id, ...d.data()} as BOMItem))); };

  // Initial Fetch for static data
  useEffect(() => { refreshParts(); }, []);
  useEffect(() => { refreshWorkplaces(); }, []);
  useEffect(() => { refreshMissingReasons(); }, []);
  useEffect(() => { refreshBOM(); }, []);

  // Realtime needed for Requests & Breaks & Roles (Admin/Mgmt stuff)
  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'break_schedules')); return onSnapshot(q, s => setBreakSchedules(s.docs.map(d => ({id:d.id, ...d.data()} as BreakSchedule)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'notifications')); return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); }, []);

  // System breaks needs to be realtime for calculations
  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
          setIsBreakActive(breaks.some(b => b.isActive));
      }); 
  }, []);

  // Roles & Permissions (Keep realtime to update UI instantly)
  useEffect(() => {
      const q = query(collection(db, 'roles'));
      return onSnapshot(q, (snapshot) => {
          const fetchedRoles = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Role));

          const legacyRoles = ['SUPERVISOR', 'LOGISTICIAN'];
          const uniqueRolesMap = new Map<string, Role>();
          const toDeleteIds: string[] = [];

          // 1. Identify duplicates and legacy roles
          fetchedRoles.forEach(role => {
              const name = role.name.toUpperCase();

              if (legacyRoles.includes(name)) {
                  toDeleteIds.push(role.id);
                  return;
              }

              if (uniqueRolesMap.has(name)) {
                  const existing = uniqueRolesMap.get(name)!;
                  // Prefer system roles, or keep the existing one
                  if (existing.isSystem && !role.isSystem) {
                      toDeleteIds.push(role.id);
                  } else if (!existing.isSystem && role.isSystem) {
                      toDeleteIds.push(existing.id);
                      uniqueRolesMap.set(name, role);
                  } else {
                      // Duplicate of same type, delete current
                      toDeleteIds.push(role.id);
                  }
              } else {
                  uniqueRolesMap.set(name, role);
              }
          });

          // 2. Cleanup Duplicates in DB
          if (toDeleteIds.length > 0) {
              const batch = writeBatch(db);
              toDeleteIds.forEach(id => {
                  batch.delete(doc(db, 'roles', id));
              });
              batch.commit().catch(e => console.error("Error cleaning duplicates", e));
          }

          const validRoles = Array.from(uniqueRolesMap.values());

          if (validRoles.length === 0 && fetchedRoles.length === 0) seedRolesAndPermissions();
          else setRoles(validRoles);
      });
  }, []);

  useEffect(() => {
      const q = query(collection(db, 'permissions'));
      return onSnapshot(q, (snapshot) => {
          setPermissions(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Permission)));
      });
  }, []);

  // Break Logic
  useEffect(() => {
      if (!breakSchedules.length) return;
      const checkTime = () => {
          const now = new Date();
          const hours = String(now.getHours()).padStart(2, '0');
          const minutes = String(now.getMinutes()).padStart(2, '0');
          const currentHM = `${hours}:${minutes}`;

          const matchingSchedule = breakSchedules.find(s => currentHM >= s.start && currentHM < s.end);
          if (matchingSchedule && !isBreakActive) {
              const recentlyCreated = systemBreaks.some(sb => sb.isActive && Math.abs(sb.start - Date.now()) < 60000);
              if (!recentlyCreated) addDoc(collection(db, 'system_breaks'), { start: Date.now(), isActive: true });
          }

          const matchingEnd = breakSchedules.find(s => s.end === currentHM);
          const isInsideAnySchedule = breakSchedules.some(s => currentHM >= s.start && currentHM < s.end);
          if ((matchingEnd || !isInsideAnySchedule) && isBreakActive) {
              const activeBreak = systemBreaks.find(b => b.isActive);
              if (activeBreak) updateDoc(doc(db, 'system_breaks', activeBreak.id), { end: Date.now(), isActive: false });
          }
      };
      const interval = setInterval(checkTime, 10000); 
      return () => clearInterval(interval);
  }, [breakSchedules, isBreakActive, systemBreaks]);

  const seedDatabase = async () => {
      await addDoc(collection(db, 'users'), { username: 'USER', password: '123', role: 'USER' });
      await addDoc(collection(db, 'users'), { username: 'ADMIN', password: '321', role: 'ADMIN' });
      const b = writeBatch(db);
      initialParts.forEach(p => b.set(doc(collection(db, 'parts')), { value: p }));
      initialWorkplaces.forEach(w => b.set(doc(collection(db, 'workplaces')), { value: w }));
      seedMissingReasons.forEach(r => b.set(doc(collection(db, 'missing_reasons')), { value: r }));
      await b.commit();
      refreshParts(); refreshWorkplaces(); refreshMissingReasons(); // Manual refresh after seed
  };

  const seedRolesAndPermissions = async () => {
      const batch = writeBatch(db);
      const roleDefs = [
          { name: 'ADMIN', isSystem: true },
          { name: 'USER', isSystem: true },
          { name: 'LEADER', isSystem: true }
      ];
      const roleMap: Record<string, string> = {};

      for (const r of roleDefs) {
          const ref = doc(db, 'roles', r.name); 
          batch.set(ref, r);
          roleMap[r.name] = ref.id;
      }

      const allPerms = [
          'perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_missing', 'perm_tab_permissions',
          'perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_cancel_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_return', 'perm_btn_lock',
          'perm_view_fullscreen', 'perm_play_sound', 'perm_view_passwords',
          'perm_manage_users', 'perm_manage_db', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'
      ];

      const assign = (role: string, list: string[]) => {
          const rid = roleMap[role];
          if (!rid) return;
          list.forEach(p => batch.set(doc(collection(db, 'permissions')), { roleId: rid, permissionName: p }));
      };

      assign('ADMIN', allPerms);
      assign('USER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_finish', 'perm_play_sound']);
      assign('LEADER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_incorrect', 'perm_btn_edit', 'perm_btn_return', 'perm_play_sound']); 

      await batch.commit();
  };

  // --- ACTIONS ---

  const handleLogin = (u: string, r: any) => { setIsAuthenticated(true); setCurrentUser(u); setCurrentUserRole(r); localStorage.setItem('app_user', u); localStorage.setItem('app_role', r); };
  const handleLogout = () => { setIsAuthenticated(false); setCurrentUser(''); setCurrentUserRole('USER'); localStorage.removeItem('app_user'); localStorage.removeItem('app_role'); };
  const handleAddUser = (u: UserData) => addDoc(collection(db, 'users'), u);
  const handleUpdatePassword = (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {password: p}); };
  const handleUpdateUserRole = (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {role: r}); };
  const handleDeleteUser = (u: string) => { const user = users.find(us => us.username === u); if(user) deleteDoc(doc(db,'users', user.id!)); };

  const handleAddPart = async (v: string) => { await addDoc(collection(db,'parts'), {value:v}); refreshParts(); };
  const handleBatchAddParts = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(v => b.set(doc(collection(db,'parts')), {value:v})); await b.commit(); refreshParts(); };
  const handleDeletePart = async (id: string) => { await deleteDoc(doc(db,'parts',id)); refreshParts(); };
  const handleDeleteAllParts = async () => { const s=await getDocs(collection(db,'parts')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshParts(); };

  const handleAddWorkplace = async (v: string, t?: number) => { await addDoc(collection(db,'workplaces'), {value:v, standardTime:t||0}); refreshWorkplaces(); };
  const handleBatchAddWorkplaces = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0})}); await b.commit(); refreshWorkplaces(); };
  const handleDeleteWorkplace = async (id: string) => { await deleteDoc(doc(db,'workplaces',id)); refreshWorkplaces(); };
  const handleDeleteAllWorkplaces = async () => { const s=await getDocs(collection(db,'workplaces')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshWorkplaces(); };

  const handleAddMissingReason = async (v: string) => { await addDoc(collection(db,'missing_reasons'), {value:v}); refreshMissingReasons(); };
  const handleDeleteMissingReason = async (id: string) => { await deleteDoc(doc(db,'missing_reasons',id)); refreshMissingReasons(); };
  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));

  const handleAddBreakSchedule = (s:string, e:string) => addDoc(collection(db,'break_schedules'), {start:s, end:e});
  const handleDeleteBreakSchedule = (id: string) => deleteDoc(doc(db,'break_schedules',id));

  const handleAddBOMItem = async (p:string, c:string, q:number) => { await addDoc(collection(db,'bom_items'), {parentPart:p, childPart:c, quantity:q}); refreshBOM(); };
  const handleBatchAddBOMItems = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const p=l.split(';'); if(p.length>=3) b.set(doc(collection(db,'bom_items')), {parentPart:p[0].trim(), childPart:p[1].trim(), quantity:parseFloat(p[2].trim().replace(',','.'))})}); await b.commit(); refreshBOM(); };
  const handleDeleteBOMItem = async (id: string) => { await deleteDoc(doc(db,'bom_items',id)); refreshBOM(); };
  const handleDeleteAllBOMItems = async () => { const s=await getDocs(collection(db,'bom_items')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); refreshBOM(); };
  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));

  const handleAddRole = (n:string) => {
      const nameUpper = n.toUpperCase();
      if (roles.some(r => r.name === nameUpper)) {
          alert("Rola s týmto názvom už existuje!");
          return;
      }
      addDoc(collection(db,'roles'), {name:nameUpper, isSystem:false});
  };
  const handleDeleteRole = async (id:string) => { await deleteDoc(doc(db,'roles',id)); const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); b.commit(); };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { const r=roles.find(ro=>ro.name===rname); if(!r)return; if(has) addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) deleteDoc(doc(db,'permissions',p.id)); } };

  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel) => {
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(unit==='boxes') fQty=`${qty} box`; 
    if(unit==='pallet') fQty=`${qty} pal`;

    let text = `${formattedDate} / ${pn}`;
    if (wp) text += ` / ${wp}`;
    if (fQty) text += ` / Počet: ${fQty}`;

    const wpObj = workplaces.find(w => w.value === wp);
    await addDoc(collection(db, 'tasks'), { 
        text: text, 
        partNumber: pn, 
        workplace: wp, 
        quantity: qty, 
        quantityUnit: unit, 
        standardTime: wpObj?.standardTime||0, 
        isDone:false, 
        priority:prio, 
        createdAt:Date.now(), 
        createdBy:currentUser 
    });
  };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false });
    }
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));

  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null,
              // MODIFIED: Do not auto-finish task when missing.
              // Just pause progress and remove blocks.
              isInProgress: false, 
              inProgressBy: null,
              isBlocked: false 
          });
          // Alert Notification
          if (isMissing) {
              await addDoc(collection(db, 'notifications'), {
                  partNumber: t.partNumber || 'Unknown',
                  reason: reason || 'Iné',
                  reportedBy: currentUser,
                  timestamp: Date.now()
              });
          }
      } 
  };

  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));

  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          updateDoc(doc(db,'tasks',id), { isBlocked, inventoryHistory:hist });
      }
  };

  const handleArchiveTasks = async () => {
      const q = query(collection(db,'tasks'), where('isDone','==',true), limit(1000));
      const s = await getDocs(q);
      const toArchive = s.docs.filter(d => !d.data().completedAt || d.data().completedAt < (Date.now() - 86400000));
      if(toArchive.length===0) return {success:true, count:0, message:"Žiadne staré úlohy."};
      const b=writeBatch(db);
      toArchive.forEach(d => { b.set(doc(collection(db,'archived_tasks')), {...d.data(), archivedAt:Date.now()}); b.delete(d.ref); });
      await b.commit();
      return {success:true, count:toArchive.length};
  };
  const fetchArchivedTasks = async () => (await getDocs(collection(db,'archived_tasks'))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onDeleteTask={handleDeleteTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={parts} workplaces={workplaces} missingReasons={missingReasons}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest}
          roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
        />
      )}
    </div>
  );
};

export default App;

