const BanIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" className={className} fill="none">
        <circle cx="12" cy="12" r="10" stroke="#DC2626" strokeWidth="2.5" fill="white" />
        <path d="M5 19L19 5" stroke="#DC2626" strokeWidth="2.5" strokeLinecap="round" />
    </svg>
);

const TaskList: React.FC<TaskListProps> = (props) => {
    const { t } = useLanguage();

    // Edit Priority Mode State (Modal)
    const [priorityEditId, setPriorityEditId] = useState<string | null>(null);

    // Missing Reason Modal State
    const [missingId, setMissingId] = useState<string | null>(null);

    // Note Modal State
    const [noteId, setNoteId] = useState<string | null>(null);
    const [noteVal, setNoteVal] = useState('');

    // Copy Feedback State
    const [copiedId, setCopiedId] = useState<string | null>(null);

    const openPriorityModal = (task: Task) => {
        setPriorityEditId(task.id);
        setMissingId(null);
        setNoteId(null);
    };

    const confirmPriority = (id: string, newPriority: PriorityLevel) => {
        const task = props.tasks.find(t => t.id === id);
        if (task) {
            // Preserve the existing text, only change priority
            props.onEditTask(id, task.text, newPriority);
        }
        setPriorityEditId(null);
    };

    const handleMissingClick = (task: Task) => {
        if (task.isMissing) {
            // Logic to cancel missing status
            if (props.hasPermission('perm_btn_cancel_missing')) {
                if (window.confirm(t('cancel_missing_confirm'))) {
                     props.onToggleMissing(task.id);
                }
            } else {
                alert(t('action_not_allowed'));
            }
        } else {
            // Standard open modal logic
            setMissingId(missingId === task.id ? null : task.id);
            setPriorityEditId(null);
            setNoteId(null);
        }
    };

    const confirmMissing = (id: string, reason: string) => {
        props.onToggleMissing(id, reason);
        setMissingId(null);
    };

    const handleNoteClick = (task: Task) => {
        setNoteId(noteId === task.id ? null : task.id);
        setNoteVal(task.note || '');
        setPriorityEditId(null);
        setMissingId(null);
    };

    const saveNote = (id: string) => {
        props.onAddNote(id, noteVal);
        setNoteId(null);
    };

    const handleCopyPart = (id: string, text: string) => {
        if (!text) return;
        navigator.clipboard.writeText(text).then(() => {
            setCopiedId(id);
            setTimeout(() => setCopiedId(null), 1500);
        }).catch(err => console.error('Copy failed', err));
    };

    return (
        <div className="flex flex-col space-y-3 pb-20">
            {props.tasks.length === 0 && (
                <div className="text-center py-12 text-gray-500 italic bg-gray-800 rounded-xl border border-gray-700">
                    {t('empty_tasks')}
                </div>
            )}

            {props.tasks.map((task) => {
                // Determine background style
                let bgClass = "";
                let borderClass = "";
                let textClass = "text-white";
                let qtyColorClass = "text-teal-400"; // Default qty color

                if (task.isDone) {
                     if (task.status === 'incorrectly_entered') {
                         bgClass = "bg-gray-800 opacity-60";
                         textClass = "text-gray-500 line-through";
                         qtyColorClass = "text-gray-500";
                     } else {
                        // Standard gray for all completed tasks (including missing ones)
                        bgClass = "bg-gray-800 opacity-80";
                        textClass = "text-gray-500 line-through";
                        qtyColorClass = "text-gray-500";
                     }
                } else {
                    if (task.isInProgress) {
                        bgClass = "bg-yellow-900/20"; // Changed to soft yellow tint
                        borderClass = "border-l-4 border-yellow-500";
                    } else if (task.isMissing) {
                        bgClass = "bg-red-800";
                        borderClass = "border-l-4 border-red-500";
                    } else if (task.priority === 'URGENT') {
                        bgClass = "bg-[#0B1121]";
                        borderClass = "border-l-4 border-red-600";
                    } else {
                        bgClass = "bg-[#0B1121]"; // Deep blue
                        borderClass = "border-l-4 border-blue-900";
                    }
                }

                return (
                    <div key={task.id} className={`group relative flex flex-col sm:flex-row rounded-lg shadow-md overflow-hidden transition-all duration-200 items-stretch ${bgClass} ${borderClass} ${!task.isDone ? 'hover:shadow-lg' : ''}`}>

                        {/* =========================================================================================
                            LEFT COLUMN: ALL DATA AND INFORMATION
                           ========================================================================================= */}
                        <div className="flex-grow p-4 flex flex-col gap-2 min-w-0">

                            {/* ROW 1: Part Number (Left) vs Quantity Group (Right) */}
                            <div className="flex justify-between items-start gap-3">
                                <h3 className={`text-2xl sm:text-3xl font-bold truncate leading-tight ${textClass}`}>
                                    {task.partNumber || task.text}
                                </h3>

                                <div className="flex flex-col items-end flex-shrink-0">
                                    {/* Capsule for Quantity */}
                                    <span className={`bg-black border border-gray-700 shadow-inner px-3 py-1 rounded-full text-xl font-bold ${qtyColorClass}`}>
                                        {task.quantity || "-"} 
                                        <span className="text-sm font-normal ml-1 text-gray-500">
                                            {task.quantityUnit === 'pcs' ? 'ks' : task.quantityUnit === 'boxes' ? 'box' : 'pal'}
                                        </span>
                                    </span>
                                    {/* Creator Info under Quantity */}
                                    <div className="text-xs text-gray-400 mt-1 font-mono text-right">
                                        <span className="font-bold text-gray-500">{task.createdBy}</span> • {new Date(task.createdAt || 0).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                                    </div>
                                </div>
                            </div>

                            {/* ROW 2: Missing Status (Between Part No and Workplace) */}
                            {task.isMissing && (
                                <div className="flex">
                                    <span className="text-red-300 flex items-center gap-1 text-xs font-bold uppercase border border-red-600/50 bg-red-900/30 px-2 py-1 rounded">
                                        <ExclamationIcon className="w-3 h-3" /> {task.missingReason}
                                    </span>
                                </div>
                            )}

                            {/* ROW 3: Workplace + Note + Completed Info */}
                            <div className="flex flex-wrap gap-2 items-center">
                                {/* Workplace */}
                                <span className={`text-lg font-bold uppercase tracking-wider ${task.isDone ? 'text-gray-600' : 'text-cyan-400'}`}>
                                    {task.workplace || "---"}
                                </span>

                                {/* Note (Pastel Yellow) */}
                                {task.note && (
                                    <span 
                                        className="inline-block px-2 py-0.5 rounded bg-[#fef9c3] text-gray-800 text-xs font-bold shadow-sm border border-yellow-200 leading-tight" 
                                        title={task.note}
                                    >
                                        {task.note}
                                    </span>
                                )}

                                {/* Completed Status */}
                                {task.isDone && !task.isMissing && (
                                    <span className="text-green-500 flex items-center gap-1 text-xs font-mono border border-green-600/30 bg-green-900/20 px-2 py-0.5 rounded">
                                        <CheckIcon className="w-3 h-3" /> {task.completedBy} • {task.completedAt ? new Date(task.completedAt).toLocaleTimeString() : ''}
                                    </span>
                                )}
                            </div>

                            {/* ROW 4: Resolving Status (Under Workplace) */}
                            {task.isInProgress && (
                                <div className="flex">
                                    <span className="text-yellow-400 text-xs font-bold uppercase tracking-wide border border-yellow-600/50 bg-yellow-900/30 px-2 py-0.5 rounded">
                                        {t('status_resolving')} {task.inProgressBy}
                                    </span>
                                </div>
                            )}
                        </div>

                        {/* =========================================================================================
                            RIGHT COLUMN: ALL BUTTONS (Actions)
                           ========================================================================================= */}
                        <div className="flex flex-shrink-0 items-center justify-center p-3 sm:border-l border-t sm:border-t-0 border-white/10 bg-black/20 sm:bg-transparent">
                            <div className="grid grid-cols-4 sm:flex sm:flex-wrap gap-2 items-center justify-center">

                                {!task.isDone ? (
                                    <>
                                        {/* Row 1: Utility Buttons */}
                                        {props.hasPermission('perm_btn_copy') && (
                                            <button 
                                                onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                className={`w-12 h-12 flex items-center justify-center rounded-lg transition-all active:scale-95 shadow-lg border ${
                                                    copiedId === task.id 
                                                    ? 'bg-green-600 border-green-500 text-white' 
                                                    : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                }`} 
                                                title={t('btn_copy')}
                                            >
                                                {copiedId === task.id ? <span className="font-bold text-xs">OK</span> : <CopyIcon className="w-6 h-6" />}
                                            </button>
                                        )}

                                        {props.hasPermission('perm_btn_note') && (
                                            <button onClick={() => handleNoteClick(task)} className={`w-12 h-12 flex items-center justify-center rounded-lg border transition-colors ${task.note ? 'bg-[#fef9c3] text-gray-800 border-yellow-200' : 'bg-gray-700 text-gray-300 border-gray-600 hover:bg-gray-600'}`} title={t('btn_note')}>
                                                <ChatIcon className="w-6 h-6" />
                                            </button>
                                        )}

                                        {/* CHANGED: Edit button -> Priority Button */}
                                        {props.hasPermission('perm_btn_edit') && (
                                            <button onClick={() => openPriorityModal(task)} className="w-12 h-12 flex items-center justify-center rounded-lg bg-gray-700 text-blue-400 border border-gray-600 hover:bg-gray-600 hover:text-white transition-colors" title="Zmeniť prioritu">
                                                <SignalIcon className="w-6 h-6" />
                                            </button>
                                        )}

                                        {props.hasPermission('perm_btn_lock') && (
                                            <button onClick={() => props.onToggleBlock(task.id)} className={`w-12 h-12 flex items-center justify-center rounded-lg transition-all active:scale-95 shadow-lg ${task.isBlocked ? 'bg-red-600 text-white border border-red-500' : 'bg-gray-700 text-gray-400 hover:bg-gray-600 border border-gray-600'}`} title={t('perm_btn_lock')}>
                                                <LockIcon className="w-6 h-6" />
                                            </button>
                                        )}

                                        {/* Row 2: Main Actions */}
                                        {props.hasPermission('perm_btn_resolve') && (
                                            <button onClick={() => props.onSetInProgress(task.id)} className={`w-14 h-14 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg ${task.isInProgress ? 'bg-yellow-600 text-white border border-yellow-500' : 'bg-gray-700 text-yellow-500 hover:bg-gray-600 border border-gray-600'}`} title={t('status_resolving')}>
                                                {task.isInProgress ? <PauseIcon className="w-8 h-8" /> : <PlayIcon className="w-8 h-8" />}
                                            </button>
                                        )}

                                        {props.hasPermission('perm_btn_missing') && (
                                            <button onClick={() => handleMissingClick(task)} className="w-14 h-14 flex items-center justify-center rounded-xl bg-gray-700 text-red-500 hover:bg-gray-600 hover:text-red-400 transition-all active:scale-95 shadow-lg border border-gray-600" title={t('perm_btn_missing')}>
                                                <ExclamationIcon className="w-8 h-8" />
                                            </button>
                                        )}

                                        {props.hasPermission('perm_btn_incorrect') && task.status !== 'incorrectly_entered' && (
                                            <button 
                                                onClick={() => { if(window.confirm(t('incorrect_confirm'))) props.onMarkAsIncorrect(task.id); }} 
                                                className="w-14 h-14 flex items-center justify-center rounded-xl bg-white transition-all active:scale-95 shadow-lg border-2 border-gray-300 hover:border-red-500 overflow-hidden" 
                                                title={t('btn_mark_incorrect')}
                                            >
                                                <BanIcon className="w-8 h-8" />
                                            </button>
                                        )}

                                        {props.hasPermission('perm_btn_finish') && (
                                            <button onClick={() => props.onToggleTask(task.id)} className="w-16 h-16 flex items-center justify-center rounded-xl bg-teal-600 text-white hover:bg-teal-500 transition-all active:scale-95 shadow-xl border border-teal-500" title={t('btn_finish')}>
                                                <CheckIcon className="w-10 h-10" />
                                            </button>
                                        )}

                                        {/* Row 3: Delete (Optional, typically separate) */}
                                        {props.hasPermission('perm_btn_delete') && (
                                            <button onClick={() => { if(window.confirm(t('miss_delete_confirm'))) props.onDeleteTask(task.id); }} className="w-12 h-12 flex items-center justify-center rounded-lg bg-red-900/50 text-red-500 hover:bg-red-800 hover:text-white border border-red-800 transition-colors" title={t('perm_btn_delete')}>
                                                <TrashIcon className="w-6 h-6" />
                                            </button>
                                        )}
                                    </>
                                ) : (
                                    /* Done Actions */
                                    <div className="flex items-center gap-2">
                                        {props.hasPermission('perm_btn_copy') && (
                                            <button 
                                                onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                className={`w-14 h-14 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${
                                                    copiedId === task.id 
                                                    ? 'bg-green-600 border-green-500 text-white' 
                                                    : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                }`} 
                                                title={t('btn_copy')}
                                            >
                                                {copiedId === task.id ? <span className="font-bold text-xs">OK</span> : <CopyIcon className="w-7 h-7" />}
                                            </button>
                                        )}
                                        {props.hasPermission('perm_btn_return') && (
                                            <button 
                                                onClick={() => props.onToggleTask(task.id)} 
                                                className="w-14 h-14 flex items-center justify-center rounded-xl bg-orange-600 hover:bg-orange-500 text-white shadow-md transition-all active:scale-95 border border-orange-500" 
                                                title={t('btn_stop')}
                                            >
                                                <ReturnIcon className="w-8 h-8" />
                                            </button>
                                        )}
                                        {props.hasPermission('perm_btn_delete') && (
                                            <button onClick={() => { if(window.confirm(t('miss_delete_confirm'))) props.onDeleteTask(task.id); }} className="w-14 h-14 flex items-center justify-center rounded-xl bg-red-900/50 text-red-500 hover:bg-red-800 hover:text-white border border-red-800 transition-colors" title={t('perm_btn_delete')}>
                                                <TrashIcon className="w-7 h-7" />
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                );
            })}

            {/* Global Modal for Priority Edit */}
            {priorityEditId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setPriorityEditId(null)}>
                    <div className="bg-gray-800 border-2 border-blue-500 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold text-blue-400 mb-6 text-center uppercase tracking-wide">{t('priority_label')}</h3>
                        <div className="grid grid-cols-1 gap-3">
                            <button 
                                onClick={() => confirmPriority(priorityEditId, 'LOW')} 
                                className="p-4 bg-slate-700 hover:bg-slate-600 border border-slate-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase"
                            >
                                {t('prio_low')}
                            </button>
                            <button 
                                onClick={() => confirmPriority(priorityEditId, 'NORMAL')} 
                                className="p-4 bg-green-700 hover:bg-green-600 border border-green-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase"
                            >
                                {t('prio_normal')}
                            </button>
                            <button 
                                onClick={() => confirmPriority(priorityEditId, 'URGENT')} 
                                className="p-4 bg-red-700 hover:bg-red-600 border border-red-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase"
                            >
                                {t('prio_urgent')}
                            </button>
                        </div>
                        <button 
                            onClick={() => setPriorityEditId(null)} 
                            className="w-full mt-6 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors"
                        >
                            {t('btn_cancel')}
                        </button>
                    </div>
                </div>,
                document.body
            )}

            {/* Global Modal for Missing Reason - Rendered via Portal to escape transforms */}
            {missingId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setMissingId(null)}>
                    <div className="bg-gray-800 border-2 border-red-600 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold text-red-400 mb-6 text-center uppercase tracking-wide">{t('modal_missing_title')}</h3>
                        <div className="grid grid-cols-1 gap-3">
                            {props.missingReasons.map(r => (
                                <button 
                                    key={r.id} 
                                    onClick={() => confirmMissing(missingId, r.value)} 
                                    className="p-4 bg-gray-700 hover:bg-red-900/30 border border-gray-600 hover:border-red-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1"
                                >
                                    {r.value}
                                </button>
                            ))}
                        </div>
                        <button 
                            onClick={() => setMissingId(null)} 
                            className="w-full mt-6 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors"
                        >
                            {t('btn_cancel')}
                        </button>
                    </div>
                </div>,
                document.body
            )}

            {/* Global Modal for Notes - Rendered via Portal */}
            {noteId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setNoteId(null)}>
                    <div className="bg-gray-800 border-2 border-yellow-500 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold text-yellow-400 mb-4 text-center uppercase tracking-wide">{t('btn_note')}</h3>
                        <textarea 
                            value={noteVal} 
                            onChange={(e) => setNoteVal(e.target.value)} 
                            className="w-full bg-gray-700 text-white p-3 rounded-lg border border-gray-600 focus:border-yellow-500 outline-none mb-4" 
                            rows={4}
                            autoFocus
                            placeholder={t('btn_note') + "..."}
                        />
                        <div className="flex gap-3">
                            <button onClick={() => saveNote(noteId)} className="flex-1 py-3 bg-yellow-600 hover:bg-yellow-500 text-white rounded-lg font-bold transition-colors">{t('btn_save')}</button>
                            <button onClick={() => setNoteId(null)} className="flex-1 py-3 bg-gray-700 hover:bg-gray-600 text-gray-300 rounded-lg font-bold transition-colors">{t('btn_cancel')}</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default TaskList;
